--MCP_INPUT:interactiveMode
--MCP_INPUT:searchText
--MCP_INPUT:generateOptions

on findCssSelectors(interactiveMode, searchText, generateOptions)
  -- Set default values
  if interactiveMode is missing value or interactiveMode is "" then
    set interactiveMode to false
  end if

  if generateOptions is missing value or generateOptions is "" then
    set generateOptions to {"shortest", "id-based", "robust", "xpath"}
  end if

  -- Make sure Chrome is running
  tell application "Google Chrome"
    if not running then
      return "error: Google Chrome is not running."
    end if

    if (count of windows) is 0 then
      return "error: No Chrome windows open."
    end if

    if (count of tabs of front window) is 0 then
      return "error: No tabs in front Chrome window."
    end if

    -- Activate Chrome to ensure it's in the foreground
    activate
  end tell

  -- Generate a unique ID for this session
  set sessionId to "mcpCssSelector_" & (random number from 100000 to 999999) as string

  if interactiveMode then
    -- Show instructions to the user via dialog
    tell application "System Events"
      display dialog "CSS Selector Finder: Interactive Mode" & return & return & "1. Click on any element in Chrome to select it" & return & "2. The script will generate optimal selectors" & return & return & "Press OK to start interactive element selection" buttons {"Cancel", "OK"} default button "OK"

      if button returned of result is "Cancel" then
        return "User canceled interactive selector finder."
      end if
    end tell
  end if

  -- Prepare the JavaScript for CSS selector finding
  set selectorScript to "
    (function() {
      try {
        // Create a namespace for our selector finder
        if (!window.mcpSelectorFinder) {
          window.mcpSelectorFinder = {
            activeSession: null,
            selectedElement: null,
            selectors: [],
            status: 'idle',
            highlightBox: null
          };
        }

        // Clear any existing session with the same ID
        if (window.mcpSelectorFinder.activeSession === '" & sessionId & "') {
          console.log('Stopping previous selector session with same ID');
          window.mcpSelectorFinder.activeSession = null;
          window.mcpSelectorFinder.selectedElement = null;
          window.mcpSelectorFinder.selectors = [];
          window.mcpSelectorFinder.status = 'idle';

          // Remove any previous highlight box
          if (window.mcpSelectorFinder.highlightBox) {
            document.body.removeChild(window.mcpSelectorFinder.highlightBox);
            window.mcpSelectorFinder.highlightBox = null;
          }

          // Remove any event listeners from previous sessions
          document.removeEventListener('click', window.mcpSelectorFinder._clickHandler);
          document.removeEventListener('mouseover', window.mcpSelectorFinder._mouseoverHandler);
          document.removeEventListener('mouseout', window.mcpSelectorFinder._mouseoutHandler);
        }

        // Set up the new session
        window.mcpSelectorFinder.activeSession = '" & sessionId & "';
        window.mcpSelectorFinder.status = 'initializing';
        window.mcpSelectorFinder.generateOptions = " & my convertListToJSArray(generateOptions) & ";

        /* ----- Selector Generation Utilities ----- */

        // Get optimal ID-based selector if available
        function getIdBasedSelector(element) {
          // If element has ID, that's the optimal selector
          if (element.id) {
            return { 
              selector: '#' + CSS.escape(element.id), 
              type: 'id-based',
              specificity: 'high',
              description: 'Direct ID selector'
            };
          }

          // Look for parent with ID, then relative path
          let current = element;
          let path = [];
          while (current && current !== document.body) {
            let parent = current.parentElement;
            if (!parent) break;

            if (parent.id) {
              // Found parent with ID, now create relative path
              const tag = element.tagName.toLowerCase();
              const index = Array.from(parent.children).filter(c => c.tagName === element.tagName).indexOf(element);

              if (index === 0 && Array.from(parent.children).filter(c => c.tagName === element.tagName).length === 1) {
                // Only one element of this type, no need for :nth-child
                path.unshift(tag);
              } else {
                // Need to use nth-child
                path.unshift(`${tag}:nth-child(${index + 1})`);
              }

              return {
                selector: `#${CSS.escape(parent.id)} > ${path.join(' > ')}`,
                type: 'id-based-parent',
                specificity: 'medium',
                description: 'Parent ID-based with child relation'
              };
            }

            // No ID found, add to path and move up
            const tag = current.tagName.toLowerCase();
            const index = Array.from(parent.children).filter(c => c.tagName === current.tagName).indexOf(current);

            if (index === 0 && Array.from(parent.children).filter(c => c.tagName === current.tagName).length === 1) {
              path.unshift(tag);
            } else {
              path.unshift(`${tag}:nth-child(${index + 1})`);
            }

            current = parent;
          }

          // No good ID-based selectors found
          return null;
        }

        // Get shortest unique path selector
        function getShortestUniqueSelector(element) {
          // Try different combination strategies from most specific to least
          const strategies = [
            // Tag + ID (if available)
            function() {
              if (element.id) {
                return `${element.tagName.toLowerCase()}#${CSS.escape(element.id)}`;
              }
              return null;
            },

            // Tag + Class (if available and unique)
            function() {
              if (element.classList.length) {
                const cls = Array.from(element.classList)
                  .map(c => `.${CSS.escape(c)}`)
                  .join('');
                const selector = `${element.tagName.toLowerCase()}${cls}`;

                // Check if unique
                if (document.querySelectorAll(selector).length === 1) {
                  return selector;
                }
              }
              return null;
            },

            // Tag + Attribute (common attributes only)
            function() {
              const attributes = ['name', 'data-test', 'data-testid', 'data-cy', 'data-qa', 'data-target'];

              for (const attr of attributes) {
                if (element.hasAttribute(attr)) {
                  const selector = `${element.tagName.toLowerCase()}[${attr}='${element.getAttribute(attr)}']`;

                  // Check if unique
                  if (document.querySelectorAll(selector).length === 1) {
                    return selector;
                  }
                }
              }
              return null;
            },

            // Try with content-based selectors (for text elements)
            function() {
              const text = element.textContent.trim();
              if (text && text.length < 50) {
                // For elements that typically contain text
                if (['P', 'H1', 'H2', 'H3', 'H4', 'H5', 'H6', 'SPAN', 'A', 'BUTTON', 'LABEL'].includes(element.tagName)) {
                  const escapedText = text.replace(/['\"]/g, '\\\\$&');

                  // Try with exact text content match
                  const selector = `${element.tagName.toLowerCase()}:contains('${escapedText}')`;

                  // This :contains selector is not standard CSS but works in jQuery
                  // We're just generating it, we'll check for uniqueness differently
                  const similarElements = Array.from(document.querySelectorAll(element.tagName))
                    .filter(el => el.textContent.trim() === text);

                  if (similarElements.length === 1) {
                    return selector;
                  }
                }
              }
              return null;
            }
          ];

          // Try each strategy until we find a unique selector
          for (const strategy of strategies) {
            const selector = strategy();
            if (selector) {
              return {
                selector: selector,
                type: 'shortest-unique',
                specificity: 'medium',
                description: 'Shortest unique element selector'
              };
            }
          }

          // If no unique simple selector, try a short path
          let current = element;
          let path = [];
          const pathLimit = 3; // Limit path depth for brevity

          while (current && current !== document.body && path.length < pathLimit) {
            const tag = current.tagName.toLowerCase();

            // Add any class that seems to be a non-utility class
            // (avoids classes likely to change like positioning utilities)
            const significantClasses = Array.from(current.classList)
              .filter(c => !c.match(/^(is-|has-|position-|d-|p-|m-|col-|row-|text-|bg-|border-|flex-|grid-|w-|h-)/))
              .map(c => `.${CSS.escape(c)}`)
              .join('');

            path.unshift(tag + significantClasses);

            // Check if the current path is unique
            const currentPath = path.join(' > ');
            if (document.querySelectorAll(currentPath).length === 1) {
              return {
                selector: currentPath,
                type: 'shortest-path',
                specificity: 'medium',
                description: 'Short path with moderate specificity'
              };
            }

            current = current.parentElement;
          }

          // No good short selector found, we'll fall back to other methods
          return null;
        }

        // Get robust selector with multiple attributes (less likely to break)
        function getRobustSelector(element) {
          // Start with tag name
          let selectorParts = [element.tagName.toLowerCase()];

          // Add ID if available
          if (element.id) {
            selectorParts.push(`#${CSS.escape(element.id)}`);
          }

          // Add classes that seem semantic (not utility classes) - limit to first 2
          const semanticClasses = Array.from(element.classList)
            .filter(c => !c.match(/^(is-|has-|position-|d-|p-|m-|col-|row-|text-|bg-|border-|flex-|grid-|w-|h-)/))
            .slice(0, 2);

          for (const cls of semanticClasses) {
            selectorParts.push(`.${CSS.escape(cls)}`);
          }

          // Add stable attributes
          const stableAttributes = ['name', 'type', 'role', 'aria-label', 'data-test', 'data-testid', 'data-target'];

          for (const attr of stableAttributes) {
            if (element.hasAttribute(attr)) {
              selectorParts.push(`[${attr}='${element.getAttribute(attr)}']`);
            }
          }

          // If we have a good robust selector at this point, use it
          const directSelector = selectorParts.join('');

          // Otherwise, create a hierarchical selector with parent context
          if (document.querySelectorAll(directSelector).length === 1) {
            return {
              selector: directSelector,
              type: 'robust-direct',
              specificity: 'high',
              description: 'Robust multi-attribute selector'
            };
          }

          // If direct selector isn't unique, add parent context
          let current = element;
          let path = [directSelector];
          const pathLimit = 2; // Limit to 2 levels up

          while (current.parentElement && current.parentElement !== document.body && path.length <= pathLimit) {
            current = current.parentElement;

            let parentSelector = current.tagName.toLowerCase();

            // Add parent ID if available
            if (current.id) {
              parentSelector += `#${CSS.escape(current.id)}`;
            } 
            // Otherwise add some classes
            else if (current.classList.length) {
              const semanticParentClasses = Array.from(current.classList)
                .filter(c => !c.match(/^(is-|has-|position-|d-|p-|m-|col-|row-|text-|bg-|border-|flex-|grid-|w-|h-)/))
                .slice(0, 1); // Limit to 1 parent class

              for (const cls of semanticParentClasses) {
                parentSelector += `.${CSS.escape(cls)}`;
              }
            }

            path.unshift(parentSelector);

            // Check if current path is unique
            const currentPath = path.join(' > ');
            if (document.querySelectorAll(currentPath).length === 1) {
              return {
                selector: currentPath,
                type: 'robust-path',
                specificity: 'high',
                description: 'Robust path-based selector with multiple attributes'
              };
            }
          }

          // Return the most specific one we have, even if not unique
          return {
            selector: path.join(' > '),
            type: 'robust-fallback',
            specificity: 'medium',
            description: 'Robust selector (may match multiple elements)',
            uniqueMatch: false
          };
        }

        // Get XPath selector for the element
        function getXPathSelector(element) {
          // Function to get XPath of element
          function getElementXPath(element) {
            if (!element) return '';

            // If element has ID, use it for a simple XPath
            if (element.id) {
              return `//*[@id='${element.id}']`;
            }

            // Otherwise, get full path to element
            let xpath = '';
            let current = element;

            while (current && current.nodeType === Node.ELEMENT_NODE) {
              let index = 0;
              let sibling = current;

              // Count previous siblings with same tag name
              while (sibling) {
                if (sibling.nodeType === Node.ELEMENT_NODE && sibling.tagName === current.tagName) {
                  index++;
                }
                sibling = sibling.previousSibling;
              }

              // Build the XPath segment
              let tagName = current.tagName.toLowerCase();
              let indexSuffix = index > 1 ? `[${index}]` : '';

              // Add any relevant attributes for better identification
              let attrs = '';
              if (current.hasAttribute('name')) {
                attrs = `[@name='${current.getAttribute('name')}']`;
              } else if (current.hasAttribute('data-testid')) {
                attrs = `[@data-testid='${current.getAttribute('data-testid')}']`;
              } else if (current.hasAttribute('role')) {
                attrs = `[@role='${current.getAttribute('role')}']`;
              }

              // If we have good attributes, use them instead of positional index
              let pathSegment = attrs ? `/${tagName}${attrs}` : `/${tagName}${indexSuffix}`;
              xpath = pathSegment + xpath;

              current = current.parentNode;

              // Break if we reach the body to avoid going all the way to document
              if (current === document.body) {
                xpath = '/html/body' + xpath;
                break;
              }
            }

            return xpath;
          }

          // Get XPath and check uniqueness
          const xpath = getElementXPath(element);
          let uniqueMatch = true;

          try {
            const result = document.evaluate(xpath, document, null, XPathResult.ORDERED_NODE_SNAPSHOT_TYPE, null);
            uniqueMatch = result.snapshotLength === 1;
          } catch (e) {
            console.error('Error evaluating XPath:', e);
            uniqueMatch = false;
          }

          return {
            selector: xpath,
            type: 'xpath',
            specificity: 'high',
            description: 'XPath selector for the element',
            uniqueMatch: uniqueMatch
          };
        }

        // Find all elements containing a specific text
        function findElementsByText(searchText) {
          if (!searchText) return [];

          // Get all visible text nodes
          const textNodes = [];
          const walker = document.createTreeWalker(
            document.body,
            NodeFilter.SHOW_TEXT,
            {
              acceptNode: function(node) {
                // Skip script and style elements
                if (['SCRIPT', 'STYLE', 'NOSCRIPT'].includes(node.parentElement.tagName)) {
                  return NodeFilter.FILTER_REJECT;
                }

                // Check if text content matches and the element is visible
                if (node.textContent.trim() && 
                    node.textContent.toLowerCase().includes(searchText.toLowerCase())) {
                  const computedStyle = window.getComputedStyle(node.parentElement);
                  if (computedStyle.display !== 'none' && 
                      computedStyle.visibility !== 'hidden' && 
                      computedStyle.opacity !== '0') {
                    return NodeFilter.FILTER_ACCEPT;
                  }
                }

                return NodeFilter.FILTER_REJECT;
              }
            }
          );

          while (walker.nextNode()) {
            textNodes.push(walker.currentNode);
          }

          // Map to parent elements
          return textNodes.map(node => {
            const element = node.parentElement;
            const exactMatch = node.textContent.trim().toLowerCase() === searchText.toLowerCase();

            return {
              element: element,
              text: node.textContent.trim(),
              exactMatch: exactMatch,
              visible: true,
              attributes: {
                tagName: element.tagName.toLowerCase(),
                id: element.id || null,
                className: element.className || null
              }
            };
          });
        }

        // Generate all selectors for an element
        function generateSelectorsForElement(element) {
          const selectors = [];
          const options = window.mcpSelectorFinder.generateOptions;

          // Add different selector strategies based on options
          if (options.includes('id-based')) {
            const idSelector = getIdBasedSelector(element);
            if (idSelector) selectors.push(idSelector);
          }

          if (options.includes('shortest')) {
            const shortestSelector = getShortestUniqueSelector(element);
            if (shortestSelector) selectors.push(shortestSelector);
          }

          if (options.includes('robust')) {
            const robustSelector = getRobustSelector(element);
            if (robustSelector) selectors.push(robustSelector);
          }

          if (options.includes('xpath')) {
            const xpathSelector = getXPathSelector(element);
            if (xpathSelector) selectors.push(xpathSelector);
          }

          // Add basic tag selector as fallback
          let basicSelector = element.tagName.toLowerCase();

          // Add nth-child if there are siblings of the same type
          const siblings = Array.from(element.parentNode.children).filter(c => c.tagName === element.tagName);
          if (siblings.length > 1) {
            const index = siblings.indexOf(element) + 1;
            basicSelector += `:nth-child(${index})`;
          }

          selectors.push({
            selector: basicSelector,
            type: 'basic',
            specificity: 'low',
            description: 'Basic element type selector' + (siblings.length > 1 ? ' with position' : '')
          });

          return selectors;
        }

        /* ----- Interactive Mode Utilities ----- */

        // Create highlight box for element hover
        function createHighlightBox() {
          const box = document.createElement('div');
          box.style.position = 'absolute';
          box.style.border = '2px solid #00a8ff';
          box.style.backgroundColor = 'rgba(0, 168, 255, 0.1)';
          box.style.pointerEvents = 'none';
          box.style.zIndex = '999999';
          box.style.borderRadius = '2px';
          box.style.boxShadow = '0 0 0 2000px rgba(0, 0, 0, 0.05)';
          box.style.transition = 'all 0.2s';
          box.style.display = 'none';
          document.body.appendChild(box);
          return box;
        }

        // Update highlight box position for an element
        function updateHighlightBox(element) {
          if (!window.mcpSelectorFinder.highlightBox) {
            window.mcpSelectorFinder.highlightBox = createHighlightBox();
          }

          const box = window.mcpSelectorFinder.highlightBox;
          const rect = element.getBoundingClientRect();

          box.style.left = rect.left + window.pageXOffset + 'px';
          box.style.top = rect.top + window.pageYOffset + 'px';
          box.style.width = rect.width + 'px';
          box.style.height = rect.height + 'px';
          box.style.display = 'block';
        }

        // Set up click handler for interactive mode
        function setupInteractiveMode() {
          // Create element hover highlight
          const box = createHighlightBox();
          window.mcpSelectorFinder.highlightBox = box;

          // Hover handler
          window.mcpSelectorFinder._mouseoverHandler = function(e) {
            e.stopPropagation();
            updateHighlightBox(e.target);
          };

          // Mouse out handler
          window.mcpSelectorFinder._mouseoutHandler = function(e) {
            e.stopPropagation();
            if (window.mcpSelectorFinder.highlightBox) {
              window.mcpSelectorFinder.highlightBox.style.display = 'none';
            }
          };

          // Click handler
          window.mcpSelectorFinder._clickHandler = function(e) {
            e.preventDefault();
            e.stopPropagation();

            // Store selected element
            window.mcpSelectorFinder.selectedElement = e.target;

            // Generate selectors
            window.mcpSelectorFinder.selectors = 
              generateSelectorsForElement(window.mcpSelectorFinder.selectedElement);

            // Clean up listeners since selection is done
            document.removeEventListener('click', window.mcpSelectorFinder._clickHandler);
            document.removeEventListener('mouseover', window.mcpSelectorFinder._mouseoverHandler);
            document.removeEventListener('mouseout', window.mcpSelectorFinder._mouseoutHandler);

            // Set status to completed
            window.mcpSelectorFinder.status = 'completed';

            // Keep highlight on the selected element
            updateHighlightBox(window.mcpSelectorFinder.selectedElement);

            return false;
          };

          // Add event listeners
          document.addEventListener('click', window.mcpSelectorFinder._clickHandler, true);
          document.addEventListener('mouseover', window.mcpSelectorFinder._mouseoverHandler, true);
          document.addEventListener('mouseout', window.mcpSelectorFinder._mouseoutHandler, true);

          // Set status to active
          window.mcpSelectorFinder.status = 'interactive';

          return {
            success: true,
            message: 'Interactive selector finder started - click on an element to select it',
            interactiveMode: true,
            sessionId: window.mcpSelectorFinder.activeSession
          };
        }

        /* ----- Text Search Mode ----- */

        function performTextSearch(searchText) {
          if (!searchText) {
            return {
              error: true,
              message: 'No search text provided'
            };
          }

          const elements = findElementsByText(searchText);

          if (elements.length === 0) {
            return {
              success: true,
              message: 'No elements found with text containing: ' + searchText,
              count: 0,
              elements: []
            };
          }

          // Generate selectors for the first few matches
          const maxResults = 5; // Limit to prevent excessive processing
          const results = elements.slice(0, maxResults).map(item => {
            const selectors = generateSelectorsForElement(item.element);

            return {
              text: item.text,
              exactMatch: item.exactMatch,
              elementInfo: {
                tagName: item.attributes.tagName,
                id: item.attributes.id,
                className: item.attributes.className
              },
              selectors: selectors
            };
          });

          return {
            success: true,
            message: `Found ${elements.length} element(s) with text containing: ${searchText}`,
            count: elements.length,
            results: results,
            truncated: elements.length > maxResults
          };
        }

        /* ----- Main Execution ----- */

        // Check parameters and select execution mode
        if (" & interactiveMode & ") {
          return setupInteractiveMode();
        } else if ('" & searchText & "') {
          return performTextSearch('" & searchText & "');
        } else {
          return {
            error: true,
            message: 'No mode specified. Use interactiveMode=true or provide searchText.'
          };
        }
      } catch (e) {
        return { 
          error: true, 
          message: e.toString(),
          stack: e.stack
        };
      }
    })();
  "

  -- Execute the script
  tell application "Google Chrome"
    try
      set initialResult to execute active tab of front window javascript selectorScript

      -- Check for interactive mode
      if initialResult contains "interactiveMode" then
        -- Create a script to check when element selection is complete
        set statusScript to "
          (function() {
            if (window.mcpSelectorFinder) {
              return {
                status: window.mcpSelectorFinder.status,
                selectedElement: window.mcpSelectorFinder.selectedElement ? true : false,
                selectors: window.mcpSelectorFinder.selectors
              };
            } else {
              return { error: true, message: 'Selector finder not initialized' };
            }
          })();
        "

        -- Tell user we're in interactive mode
        set messageText to "Click on any element in the Chrome window to select it for CSS selector generation."

        -- Poll for status changes with timeout
        set maxAttempts to 300 -- 2.5 minutes max wait time
        set attemptCounter to 0

        repeat
          delay 0.5
          set attemptCounter to attemptCounter + 1
          set statusCheck to execute active tab of front window javascript statusScript

          -- If selection is complete, get the selectors
          if statusCheck contains "\"status\":\"completed\"" then
            return statusCheck
          end if

          -- Timeout check
          if attemptCounter ≥ maxAttempts then
            -- Send Escape key to cancel interactive mode
            tell application "System Events"
              key code 53 -- Escape key
            end tell

            return "{\"error\": true, \"message\": \"Timed out waiting for element selection.\"}"
          end if
        end repeat
      else
        -- Return the direct result for text search or error
        return initialResult
      end if
    on error errMsg
      return "{\"error\": true, \"message\": \"" & my escapeJSString(errMsg) & "\"}"
    end try
  end tell
end findCssSelectors

-- Helper function to escape JavaScript strings
on escapeJSString(theString)
  set resultString to ""
  repeat with i from 1 to length of theString
    set currentChar to character i of theString
    if currentChar is "\"" or currentChar is "\\" then
      set resultString to resultString & "\\" & currentChar
    else if ASCII number of currentChar is 10 then
      set resultString to resultString & "\\n"
    else if ASCII number of currentChar is 13 then
      set resultString to resultString & "\\r"
    else if ASCII number of currentChar is 9 then
      set resultString to resultString & "\\t"
    else
      set resultString to resultString & currentChar
    end if
  end repeat
  return resultString
end escapeJSString

-- Helper function to convert AppleScript list to JavaScript array
on convertListToJSArray(theList)
  set jsArray to "["

  if class of theList is string then
    -- If it's a string, interpret as comma-separated values
    set AppleScript's text item delimiters to ","
    set listItems to text items of theList
    set AppleScript's text item delimiters to ""
  else
    set listItems to theList
  end if

  repeat with i from 1 to count of listItems
    set thisItem to item i of listItems

    -- Trim whitespace
    set thisItem to do shell script "echo " & quoted form of thisItem & " | xargs"

    -- Handle strings with quotes
    set jsArray to jsArray & "\"" & thisItem & "\""

    if i < count of listItems then
      set jsArray to jsArray & ", "
    end if
  end repeat

  set jsArray to jsArray & "]"
  return jsArray
end convertListToJSArray

return my findCssSelectors("--MCP_INPUT:interactiveMode", "--MCP_INPUT:searchText", "--MCP_INPUT:generateOptions")

--MCP_INPUT:deviceName
--MCP_INPUT:width
--MCP_INPUT:height
--MCP_INPUT:devicePixelRatio
--MCP_INPUT:userAgent
--MCP_INPUT:mobile

on emulateDeviceInChrome(deviceName, width, height, devicePixelRatio, userAgent, mobile)
  -- Make sure Chrome is running
  tell application "Google Chrome"
    if not running then
      return "error: Google Chrome is not running."
    end if

    if (count of windows) is 0 then
      return "error: No Chrome windows open."
    end if

    if (count of tabs of front window) is 0 then
      return "error: No tabs in front Chrome window."
    end if

    -- Activate Chrome to ensure keyboard shortcuts work
    activate
  end tell

  -- Open DevTools
  tell application "System Events"
    tell process "Google Chrome"
      set frontmost to true
      delay 0.3

      -- Check if DevTools is already open
      set devToolsOpen to false
      repeat with w in windows
        if description of w contains "Developer Tools" then
          set devToolsOpen to true
          exit repeat
        end if
      end repeat

      -- Open DevTools if not already open
      if not devToolsOpen then
        key code 34 using {command down, option down} -- Option+Command+I
        delay 0.7
      end if

      -- Toggle device toolbar with Command+Shift+M
      key code 46 using {command down, shift down} -- Command+Shift+M
      delay 0.5
    end tell
  end tell

  -- Prepare the device emulation script based on provided parameters
  if deviceName is not missing value and deviceName is not "" then
    -- Use predefined device
    set emulationScript to "
      (function() {
        try {
          const deviceName = '" & my escapeJSString(deviceName) & "';

          // Function to ensure we're in a DevTools context
          function ensureDevTools() {
            if (typeof DevToolsAPI === 'undefined') {
              // We're in the page context, not DevTools context
              // Try to execute in DevTools context via extension API if available
              if (typeof chrome !== 'undefined' && chrome.devtools) {
                chrome.devtools.inspectedWindow.eval(
                  'DevToolsAPI && DevToolsAPI.setDeviceMetricsOverride()',
                  function(result, isException) { 
                    if (isException) {
                      console.error('Failed to execute in DevTools context');
                    }
                  }
                );
                return { message: 'Attempted to execute in DevTools context via extension API' };
              }
              return { error: true, message: 'Not in DevTools context and no fallback available' };
            }
            return { success: true };
          }

          // Check if we're in DevTools context
          const devToolsCheck = ensureDevTools();
          if (devToolsCheck.error) {
            // Fallback: Use the main page's emulation API
            const devices = [
              { name: 'iPhone 13', width: 390, height: 844, devicePixelRatio: 3, userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 15_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.0 Mobile/15E148 Safari/604.1', mobile: true },
              { name: 'iPhone SE', width: 375, height: 667, devicePixelRatio: 2, userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 15_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.0 Mobile/15E148 Safari/604.1', mobile: true },
              { name: 'iPad', width: 810, height: 1080, devicePixelRatio: 2, userAgent: 'Mozilla/5.0 (iPad; CPU OS 15_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.0 Mobile/15E148 Safari/604.1', mobile: true },
              { name: 'Pixel 6', width: 412, height: 915, devicePixelRatio: 2.625, userAgent: 'Mozilla/5.0 (Linux; Android 12; Pixel 6) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/96.0.4664.104 Mobile Safari/537.36', mobile: true },
              { name: 'Samsung Galaxy S21', width: 360, height: 800, devicePixelRatio: 3, userAgent: 'Mozilla/5.0 (Linux; Android 12; SM-G998B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/96.0.4664.104 Mobile Safari/537.36', mobile: true }
            ];

            // Find the requested device
            const device = devices.find(d => d.name.toLowerCase() === deviceName.toLowerCase());

            if (!device) {
              return { error: true, message: 'Device \"' + deviceName + '\" not found in predefined devices' };
            }

            // Apply device emulation using the main page emulation API
            const result = emulateDeviceDirectly(device);
            return result;
          }

          // Use the DevTools API
          // This function tries various approaches to enable device emulation
          function emulateWithDevToolsAPI() {
            // Try with the current DevTools version API
            if (typeof DevToolsHost !== 'undefined' && typeof DevToolsAPI !== 'undefined') {
              // Method 1: Use the setDeviceMetricsOverride method if available (newer versions)
              if (typeof DevToolsAPI.setDeviceMetricsOverride === 'function') {
                const devices = DevToolsAPI.getDevicesList();
                const device = devices.find(d => d.title.toLowerCase() === deviceName.toLowerCase());

                if (device) {
                  DevToolsAPI.setDeviceMetricsOverride(device);
                  return { success: true, message: 'Device emulation set to ' + deviceName };
                } else {
                  return { error: true, message: 'Device name not found in DevTools device list' };
                }
              }

              // Method 2: Use UI automation via DevToolsAPI
              if (typeof DevToolsAPI.showPanel === 'function' && typeof UI !== 'undefined') {
                // Switch to Device Mode in DevTools
                DevToolsAPI.showPanel('device_mode');

                if (typeof UI.inspectorView !== 'undefined' && UI.inspectorView.showPanel) {
                  UI.inspectorView.showPanel('device_mode');

                  // Try to select the device from the dropdown
                  if (UI.DeviceModeModel && UI.DeviceModeModel.deviceModelSetting) {
                    UI.DeviceModeModel.deviceModelSetting.set(deviceName);
                    return { success: true, message: 'Device model set to ' + deviceName + ' via UI model' };
                  }
                }
              }
            }

            // Fallback: Use direct emulation
            const fallbackDevice = getDefaultDeviceSpecs(deviceName);
            return emulateDeviceDirectly(fallbackDevice);
          }

          // Function to get device specs for known devices
          function getDefaultDeviceSpecs(name) {
            const devices = {
              'iphone 13': { width: 390, height: 844, devicePixelRatio: 3, userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 15_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.0 Mobile/15E148 Safari/604.1', mobile: true },
              'iphone se': { width: 375, height: 667, devicePixelRatio: 2, userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 15_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.0 Mobile/15E148 Safari/604.1', mobile: true },
              'ipad': { width: 810, height: 1080, devicePixelRatio: 2, userAgent: 'Mozilla/5.0 (iPad; CPU OS 15_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.0 Mobile/15E148 Safari/604.1', mobile: true },
              'pixel 6': { width: 412, height: 915, devicePixelRatio: 2.625, userAgent: 'Mozilla/5.0 (Linux; Android 12; Pixel 6) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/96.0.4664.104 Mobile Safari/537.36', mobile: true },
              'samsung galaxy s21': { width: 360, height: 800, devicePixelRatio: 3, userAgent: 'Mozilla/5.0 (Linux; Android 12; SM-G998B) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/96.0.4664.104 Mobile Safari/537.36', mobile: true }
            };

            const deviceKey = name.toLowerCase();
            return devices[deviceKey] || { width: 375, height: 667, devicePixelRatio: 2, userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 15_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.0 Mobile/15E148 Safari/604.1', mobile: true };
          }

          // Function to directly emulate a device using page emulation API
          function emulateDeviceDirectly(device) {
            if (typeof EmulationAgent !== 'undefined') {
              // Use the protocol directly if available
              EmulationAgent.setDeviceMetricsOverride({
                width: device.width,
                height: device.height,
                deviceScaleFactor: device.devicePixelRatio,
                mobile: device.mobile,
                screenWidth: device.width,
                screenHeight: device.height
              });

              EmulationAgent.setUserAgentOverride({
                userAgent: device.userAgent
              });

              return { success: true, message: 'Device emulated using EmulationAgent' };
            } else if (typeof chrome !== 'undefined' && chrome.debugger) {
              // Try using chrome.debugger API if available (rare in this context)
              chrome.debugger.sendCommand({tabId: chrome.devtools.inspectedWindow.tabId}, 'Emulation.setDeviceMetricsOverride', {
                width: device.width, 
                height: device.height,
                deviceScaleFactor: device.devicePixelRatio,
                mobile: device.mobile
              });

              chrome.debugger.sendCommand({tabId: chrome.devtools.inspectedWindow.tabId}, 'Emulation.setUserAgentOverride', {
                userAgent: device.userAgent
              });

              return { success: true, message: 'Device emulated using chrome.debugger API' };
            } else {
              // Last resort: Try to use the window.emulationParams approach
              if (typeof window !== 'undefined') {
                window.emulationParams = {
                  deviceName: deviceName,
                  device: device
                };

                // Add a fake element to indicate success for screen scraping
                const infoDiv = document.createElement('div');
                infoDiv.id = 'mcpDeviceEmulationInfo';
                infoDiv.style.display = 'none';
                infoDiv.textContent = JSON.stringify(device);
                document.body.appendChild(infoDiv);

                return { success: true, message: 'Emulation parameters stored for later use' };
              }
            }

            return { error: true, message: 'No emulation API available' };
          }

          // Execute the emulation
          return emulateWithDevToolsAPI();
        } catch (e) {
          return { error: true, message: e.toString() };
        }
      })();
    "
  else
    -- Use custom device settings
    -- Set defaults for missing parameters
    if width is missing value or width is "" then set width to 375
    if height is missing value or height is "" then set height to 667
    if devicePixelRatio is missing value or devicePixelRatio is "" then set devicePixelRatio to 2
    if userAgent is missing value or userAgent is "" then set userAgent to "Mozilla/5.0 (iPhone; CPU iPhone OS 15_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/15.0 Mobile/15E148 Safari/604.1"
    if mobile is missing value then set mobile to true

    set emulationScript to "
      (function() {
        try {
          const customDevice = {
            width: " & width & ",
            height: " & height & ",
            devicePixelRatio: " & devicePixelRatio & ",
            userAgent: '" & my escapeJSString(userAgent) & "',
            mobile: " & mobile & "
          };

          // Function to directly emulate a device using page emulation API
          function emulateDeviceDirectly(device) {
            if (typeof EmulationAgent !== 'undefined') {
              // Use the protocol directly if available
              EmulationAgent.setDeviceMetricsOverride({
                width: device.width,
                height: device.height,
                deviceScaleFactor: device.devicePixelRatio,
                mobile: device.mobile,
                screenWidth: device.width,
                screenHeight: device.height
              });

              EmulationAgent.setUserAgentOverride({
                userAgent: device.userAgent
              });

              return { success: true, message: 'Custom device emulated using EmulationAgent' };
            } else if (typeof chrome !== 'undefined' && chrome.debugger) {
              // Try using chrome.debugger API if available
              chrome.debugger.sendCommand({tabId: chrome.devtools.inspectedWindow.tabId}, 'Emulation.setDeviceMetricsOverride', {
                width: device.width, 
                height: device.height,
                deviceScaleFactor: device.devicePixelRatio,
                mobile: device.mobile
              });

              chrome.debugger.sendCommand({tabId: chrome.devtools.inspectedWindow.tabId}, 'Emulation.setUserAgentOverride', {
                userAgent: device.userAgent
              });

              return { success: true, message: 'Custom device emulated using chrome.debugger API' };
            } else {
              // Last resort: Set parameters and try to use UI automation
              window.customEmulationParams = device;

              // Add a marker element for screen scraping
              const infoDiv = document.createElement('div');
              infoDiv.id = 'mcpDeviceEmulationInfo';
              infoDiv.style.display = 'none';
              infoDiv.textContent = JSON.stringify(device);
              document.body.appendChild(infoDiv);

              return { success: true, message: 'Custom emulation parameters set' };
            }

            return { error: true, message: 'No emulation API available' };
          }

          return emulateDeviceDirectly(customDevice);
        } catch (e) {
          return { error: true, message: e.toString() };
        }
      })();
    "
  end if

  -- Execute the emulation script
  tell application "Google Chrome"
    try
      set emulationResult to execute active tab of front window javascript emulationScript

      -- Check the result
      if emulationResult contains "error" then
        return "error: " & emulationResult
      else
        -- Try to get the device info using a follow-up script
        set infoScript to "
          (function() {
            const infoElement = document.getElementById('mcpDeviceEmulationInfo');
            if (infoElement) {
              const info = infoElement.textContent;
              try {
                return JSON.parse(info);
              } catch(e) {
                return info;
              }
            }

            // Check for stored emulation parameters
            if (window.emulationParams) {
              return window.emulationParams;
            } else if (window.customEmulationParams) {
              return window.customEmulationParams;
            }

            return null;
          })();
        "

        set deviceInfo to execute active tab of front window javascript infoScript

        if deviceName is not missing value and deviceName is not "" then
          return "Successfully configured emulation for device: " & deviceName
        else
          return "Successfully configured custom device emulation with settings: width=" & width & ", height=" & height & ", devicePixelRatio=" & devicePixelRatio
        end if
      end if
    on error errMsg
      return "error: Failed to configure device emulation - " & errMsg
    end try
  end tell
end emulateDeviceInChrome

-- Helper function to escape JavaScript strings
on escapeJSString(theString)
  set resultString to ""
  repeat with i from 1 to length of theString
    set currentChar to character i of theString
    if currentChar is "'" or currentChar is "\"" or currentChar is "\\" then
      set resultString to resultString & "\\" & currentChar
    else
      set resultString to resultString & currentChar
    end if
  end repeat
  return resultString
end escapeJSString

return my emulateDeviceInChrome("--MCP_INPUT:deviceName", "--MCP_INPUT:width", "--MCP_INPUT:height", "--MCP_INPUT:devicePixelRatio", "--MCP_INPUT:userAgent", "--MCP_INPUT:mobile")

--MCP_INPUT:jsCode
--MCP_INPUT:awaitPromises

on executeJSInChromeConsole(javascriptCode, awaitPromises)
  if javascriptCode is missing value or javascriptCode is "" then
    return "error: No JavaScript code provided."
  end if

  -- Default awaitPromises to false if not provided
  if awaitPromises is missing value then
    set awaitPromises to false
  end if

  -- Make sure Chrome is running
  tell application "Google Chrome"
    if not running then
      return "error: Google Chrome is not running."
    end if

    if (count of windows) is 0 then
      return "error: No Chrome windows open."
    end if

    if (count of tabs of front window) is 0 then
      return "error: No tabs in front Chrome window."
    end if

    -- Activate Chrome to ensure keyboard shortcuts work
    activate
  end tell

  -- First, ensure DevTools is open and console is visible
  tell application "System Events"
    tell process "Google Chrome"
      set frontmost to true
      delay 0.3

      -- Check if DevTools is already open (approximate detection)
      set devToolsOpen to false
      repeat with w in windows
        if description of w contains "Developer Tools" or description of w contains "Console" then
          set devToolsOpen to true
          exit repeat
        end if
      end repeat

      -- Open DevTools if not already open
      if not devToolsOpen then
        key code 34 using {command down, option down} -- Option+Command+I
        delay 0.7
      end if

      -- Switch to Console panel
      key code 38 using {command down, option down} -- Option+Command+J
      delay 0.5
    end tell
  end tell

  -- Prepare the JavaScript code for execution
  -- By using a unique ID, we can identify our execution result
  set uniqueID to "mcpExecute_" & (random number from 100000 to 999999) as string

  -- Wrap the provided code to capture its result and handle errors
  set wrappedCode to "
    (function() {
      try {
        // Make sure we're in a DevTools context
        if (typeof console === 'undefined') {
          return { 
            error: true, 
            message: 'Console not available. DevTools API may not be accessible.' 
          };
        }

        // Clear console for cleaner output
        console.clear();

        // Define a function to execute user code and handle promise results
        const executeUserCode = async () => {
          try {
            // Execute user code and capture result
            let result = (function() { " & javascriptCode & " })();

            " & (if awaitPromises then "
            // Handle promises if awaitPromises is true
            if (result instanceof Promise) {
              result = await result;
            }
            " else "") & "

            // Handle special case for undefined
            if (result === undefined) {
              return { result: null, type: 'undefined' };
            }

            // Convert result to serialized object with type info
            return { 
              result: result, 
              type: typeof result,
              isArray: Array.isArray(result),
              isObject: (typeof result === 'object' && result !== null)
            };
          } catch (e) {
            return { 
              error: true, 
              message: e.message,
              stack: e.stack,
              name: e.name 
            };
          }
        };

        // Custom handling based on whether we need to await promises
        " & (if awaitPromises then "
        // Execute code asynchronously and store result for retrieval
        executeUserCode().then(result => {
          // Store result in sessionStorage for retrieval
          window.sessionStorage.setItem('" & uniqueID & "', JSON.stringify(result));
          console.log('%cCode execution completed (" & uniqueID & ")', 'color:green;font-weight:bold');
        }).catch(err => {
          window.sessionStorage.setItem('" & uniqueID & "', JSON.stringify({ 
            error: true, 
            message: err.message,
            stack: err.stack,
            name: err.name 
          }));
          console.error('Execution error:', err);
        });

        return { 
          status: 'executing', 
          message: 'Code execution started. Awaiting promise resolution.',
          executionId: '" & uniqueID & "'
        };
        " else "
        // Execute code synchronously
        const result = executeUserCode();

        // Store result in sessionStorage for reliability
        window.sessionStorage.setItem('" & uniqueID & "', JSON.stringify(result));

        return result;
        ") & "
      } catch (e) {
        return { 
          error: true, 
          message: e.message,
          stack: e.stack,
          name: e.name 
        };
      }
    })();
  "

  tell application "Google Chrome"
    try
      -- Execute our wrapped code
      set initialResult to execute active tab of front window javascript wrappedCode

      -- Handle async execution (when awaiting promises)
      if awaitPromises then
        -- Check if we have a pending execution to retrieve
        if initialResult is not missing value and initialResult contains "executing" then
          set executionId to uniqueID

          -- Function to retrieve the result
          set getResultCode to "
            (function() {
              const resultStr = window.sessionStorage.getItem('" & executionId & "');
              if (resultStr) {
                // Clear the result from sessionStorage to avoid memory leaks
                window.sessionStorage.removeItem('" & executionId & "');
                return JSON.parse(resultStr);
              } else {
                return { status: 'pending', message: 'Result not ready yet' };
              }
            })();
          "

          -- Poll for the result with timeout
          set maxAttempts to 30 -- 15 seconds max wait time
          set attemptCounter to 0

          repeat
            delay 0.5
            set attemptCounter to attemptCounter + 1
            set resultCheck to execute active tab of front window javascript getResultCode

            -- If we got a result back that's not 'pending', we're done
            if resultCheck is not missing value and resultCheck does not contain "pending" then
              return resultCheck
            end if

            -- Timeout check
            if attemptCounter ≥ maxAttempts then
              return "{\"error\": true, \"message\": \"Execution timed out waiting for promise resolution.\"}"
            end if
          end repeat
        else
          -- Return the initial result if not an async execution
          return initialResult
        end if
      else
        -- For synchronous execution, return the result directly
        return initialResult
      end if
    on error errMsg
      return "{\"error\": true, \"message\": \"" & my escapeJSString(errMsg) & "\"}"
    end try
  end tell
end executeJSInChromeConsole

-- Helper function to escape JavaScript strings
on escapeJSString(theString)
  set resultString to ""
  repeat with i from 1 to length of theString
    set currentChar to character i of theString
    if currentChar is "\"" or currentChar is "\\" then
      set resultString to resultString & "\\" & currentChar
    else if ASCII number of currentChar is 10 then
      set resultString to resultString & "\\n"
    else if ASCII number of currentChar is 13 then
      set resultString to resultString & "\\r"
    else if ASCII number of currentChar is 9 then
      set resultString to resultString & "\\t"
    else
      set resultString to resultString & currentChar
    end if
  end repeat
  return resultString
end escapeJSString

return my executeJSInChromeConsole("--MCP_INPUT:jsCode", "--MCP_INPUT:awaitPromises")

// Chrome Form Filler
// Fills web forms with provided data in Chrome

function run(argv) {
    // Default parameters when run without arguments
    if (argv.length === 0) {
        // Launch interactive mode with UI
        return runInteractiveMode();
    }

    return "Please use with MCP parameters";
}

// Main handler for MCP input parameters
function processMCPParameters(params) {
    try {
        // Extract parameters
        const url = params.url || "";                      // URL to open
        const formData = params.formData || {};            // Data to fill in form
        const selectors = params.selectors || {};          // Custom selectors
        const submit = params.submit === true;             // Whether to auto-submit
        const waitTime = params.waitTime || 5;             // Wait time in seconds after page load
        const fillDelay = params.fillDelay || 0.1;         // Delay between filling fields (seconds)

        // Validate required parameters
        if (!url) {
            return {
                success: false,
                error: "URL is required"
            };
        }

        if (Object.keys(formData).length === 0) {
            return {
                success: false,
                error: "Form data is required"
            };
        }

        // Fill the form
        return fillForm(url, formData, selectors, submit, waitTime, fillDelay);
    } catch (error) {
        return {
            success: false,
            error: `Error processing parameters: ${error.message}`
        };
    }
}

// Function to run interactive mode with dialog interfaces
function runInteractiveMode() {
    try {
        const app = Application.currentApplication();
        app.includeStandardAdditions = true;

        // Enter URL
        const url = app.displayDialog("Enter the website URL:", {
            defaultAnswer: "https://",
            withIcon: "note",
            buttons: ["Cancel", "Next"],
            defaultButton: "Next"
        }).textReturned;

        if (!url || !url.startsWith("http")) {
            return "Invalid URL. Please enter a URL starting with http:// or https://";
        }

        // Gather form data through dialogs
        let formData = {};
        let continueAdding = true;

        while (continueAdding) {
            const fieldName = app.displayDialog("Enter field name/label (or Cancel to finish):", {
                defaultAnswer: "",
                withIcon: "note",
                buttons: ["Finish", "Add Field"],
                defaultButton: "Add Field"
            });

            if (fieldName.buttonReturned === "Finish") {
                continueAdding = false;
                continue;
            }

            const fieldValue = app.displayDialog(`Enter value for "${fieldName.textReturned}":`, {
                defaultAnswer: "",
                withIcon: "note",
                buttons: ["Cancel", "Add"],
                defaultButton: "Add"
            });

            formData[fieldName.textReturned] = fieldValue.textReturned;
        }

        // Ask about submission
        const shouldSubmit = app.displayDialog("Would you like to automatically submit the form?", {
            withIcon: "note",
            buttons: ["No", "Yes"],
            defaultButton: "No"
        }).buttonReturned === "Yes";

        // Fill the form
        return fillForm(url, formData, {}, shouldSubmit, 5, 0.5);
    } catch (error) {
        if (error.errorNumber === -128) {
            return "Cancelled by user";
        }
        return `Error in interactive mode: ${error.message}`;
    }
}

// Main function to fill a form
function fillForm(url, formData, selectors, submit, waitTime, fillDelay) {
    try {
        const chrome = Application("Google Chrome");
        chrome.includeStandardAdditions = true;

        // Activate Chrome
        chrome.activate();

        // Open URL in a new tab
        chrome.windows[0].makeNewTab({with: url});
        delay(1); // Short delay to ensure tab opens
        const tabCount = chrome.windows[0].tabs.length;
        chrome.windows[0].activeTabIndex = tabCount;

        // Wait for page to load
        delay(waitTime);

        // Get the JavaScript to execute
        const jsScript = buildFormFillScript(formData, selectors, submit, fillDelay);

        // Execute the JavaScript in Chrome
        const result = chrome.windows[0].activeTab.execute({javascript: jsScript});

        return {
            success: true,
            message: "Form filled successfully",
            result: result
        };
    } catch (error) {
        return {
            success: false,
            error: `Error filling form: ${error.message}`
        };
    }
}

// Create the JavaScript to run in the browser context
function buildFormFillScript(formData, selectors, submit, fillDelay) {
    const customSelectors = JSON.stringify(selectors);
    const formDataJson = JSON.stringify(formData);
    const delayMs = fillDelay * 1000;

    return `
    (function() {
        // Form fill function
        const formData = ${formDataJson};
        const customSelectors = ${customSelectors};
        const shouldSubmit = ${submit};
        const fieldDelay = ${delayMs};

        // Helper function to delay execution
        const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

        // Helper function to find input elements
        async function findInputElement(fieldName) {
            // First, check if we have a custom selector for this field
            if (customSelectors[fieldName]) {
                return document.querySelector(customSelectors[fieldName]);
            }

            // Try various selector methods to find the input
            // 1. Try by ID
            let element = document.getElementById(fieldName);
            if (element) return element;

            // 2. Try by name attribute
            element = document.querySelector(\`[name="\${fieldName}"]\`);
            if (element) return element;

            // 3. Try by placeholder text
            element = document.querySelector(\`[placeholder*="\${fieldName}"]\`);
            if (element) return element;

            // 4. Try by aria-label
            element = document.querySelector(\`[aria-label*="\${fieldName}"]\`);
            if (element) return element;

            // 5. Try finding a label element containing the field name
            const labels = Array.from(document.querySelectorAll('label'));
            for (const label of labels) {
                if (label.textContent.toLowerCase().includes(fieldName.toLowerCase())) {
                    // If label has a 'for' attribute, use it to find the input
                    if (label.htmlFor) {
                        element = document.getElementById(label.htmlFor);
                        if (element) return element;
                    }

                    // Check for inputs inside the label
                    const inputInLabel = label.querySelector('input, select, textarea');
                    if (inputInLabel) return inputInLabel;

                    // Check for inputs after the label
                    let sibling = label.nextElementSibling;
                    while (sibling) {
                        if (sibling.matches('input, select, textarea')) {
                            return sibling;
                        }
                        // Check for input inside the sibling
                        const nestedInput = sibling.querySelector('input, select, textarea');
                        if (nestedInput) return nestedInput;

                        sibling = sibling.nextElementSibling;
                    }
                }
            }

            // 6. Try by class or name containing the field name
            element = document.querySelector(\`[class*="\${fieldName}"]\`) || 
                      document.querySelector(\`[name*="\${fieldName}"]\`);
            if (element) return element;

            // 7. Try by input type for common fields
            const commonFields = {
                'email': 'input[type="email"]',
                'password': 'input[type="password"]',
                'username': 'input[type="text"], input:not([type])',
                'search': 'input[type="search"]',
                'phone': 'input[type="tel"]',
                'date': 'input[type="date"]'
            };

            if (commonFields[fieldName.toLowerCase()]) {
                element = document.querySelector(commonFields[fieldName.toLowerCase()]);
                if (element) return element;
            }

            return null;
        }

        // Function to set value based on element type
        async function setValue(element, value) {
            if (!element) return false;

            const tagName = element.tagName.toLowerCase();
            const inputType = element.type ? element.type.toLowerCase() : '';

            // Handle different input types
            if (tagName === 'select') {
                // For select elements, find the option that matches the value
                const options = Array.from(element.options);
                for (const option of options) {
                    if (option.text.includes(value) || option.value.includes(value)) {
                        element.value = option.value;
                        element.dispatchEvent(new Event('change', { bubbles: true }));
                        return true;
                    }
                }
                return false;
            } 
            else if (inputType === 'checkbox' || inputType === 'radio') {
                // For checkboxes and radios
                const lowercaseValue = value.toString().toLowerCase();
                const shouldCheck = ['true', 'yes', 'on', '1'].includes(lowercaseValue);
                element.checked = shouldCheck;
                element.dispatchEvent(new Event('change', { bubbles: true }));
                return true;
            }
            else if (tagName === 'textarea' || tagName === 'input') {
                // Clear the current value first
                element.value = '';
                element.dispatchEvent(new Event('input', { bubbles: true }));
                await sleep(50); // Small delay after clearing

                // Set the new value
                element.value = value;

                // Dispatch events to trigger any listeners
                element.dispatchEvent(new Event('input', { bubbles: true }));
                element.dispatchEvent(new Event('change', { bubbles: true }));
                return true;
            }
            else {
                // For other elements, try setting innerText or textContent
                if (typeof element.value !== 'undefined') {
                    element.value = value;
                } else {
                    element.textContent = value;
                }
                return true;
            }
        }

        // Main function to fill the form
        async function fillForm() {
            let results = {};
            let errors = [];

            for (const fieldName of Object.keys(formData)) {
                try {
                    // Find the element
                    const element = await findInputElement(fieldName);

                    if (!element) {
                        errors.push(\`Could not find element for: \${fieldName}\`);
                        continue;
                    }

                    // Set the value
                    const success = await setValue(element, formData[fieldName]);

                    if (success) {
                        results[fieldName] = 'filled';
                    } else {
                        errors.push(\`Could not set value for: \${fieldName}\`);
                    }

                    // Add delay between fields
                    if (fieldDelay > 0) {
                        await sleep(fieldDelay);
                    }
                } catch (error) {
                    errors.push(\`Error processing \${fieldName}: \${error.message}\`);
                }
            }

            // Submit the form if requested
            if (shouldSubmit) {
                try {
                    // Try to find the submit button
                    let submitButton = document.querySelector('button[type="submit"]') || 
                                      document.querySelector('input[type="submit"]');

                    // If no submit button found, look for buttons with submit-related text
                    if (!submitButton) {
                        const buttons = Array.from(document.querySelectorAll('button, input[type="button"], a.button, .btn, [role="button"]'));
                        for (const button of buttons) {
                            const text = button.textContent.toLowerCase();
                            if (text.includes('submit') || text.includes('login') || 
                                text.includes('sign in') || text.includes('continue') ||
                                text.includes('register') || text.includes('next')) {
                                submitButton = button;
                                break;
                            }
                        }
                    }

                    // If we found a submit button, click it
                    if (submitButton) {
                        submitButton.click();
                        results['formSubmitted'] = true;
                    } else {
                        // If no button found, try to submit the form directly
                        const form = document.querySelector('form');
                        if (form) {
                            form.submit();
                            results['formSubmitted'] = true;
                        } else {
                            errors.push('Could not find a submit button or form element');
                        }
                    }
                } catch (error) {
                    errors.push(\`Error submitting form: \${error.message}\`);
                }
            }

            return {
                success: errors.length === 0,
                filled: results,
                errors: errors
            };
        }

        // Execute the form filling and return the result
        return fillForm();
    })();
    `;
}

// Utility function to create a delay
function delay(seconds) {
    const app = Application.currentApplication();
    app.includeStandardAdditions = true;
    app.delay(seconds);
}

