              const originalXHROpen = XMLHttpRequest.prototype.open;
              const originalXHRSend = XMLHttpRequest.prototype.send;

              // Intercept fetch API
              window.fetch = async function(resource, options) {
                let url = resource;
                if (typeof resource === 'object' && resource.url) {
                  url = resource.url;
                }

                // For monitoring mode, just record the request
                if (window.mcpNetworkInterception.isMonitoring) {
                  // Clone request to extract body if available
                  const request = resource instanceof Request ? resource : new Request(resource, options);
                  let requestBody = '';

                  try {
                    const clonedRequest = request.clone();
                    if (['POST', 'PUT', 'PATCH'].includes(request.method)) {
                      requestBody = await clonedRequest.text();
                    }
                  } catch (e) {
                    console.error('Failed to extract request body:', e);
                  }

                  window.mcpNetworkInterception.records.push({
                    url: url.toString(),
                    method: request.method,
                    requestHeaders: request.headers ? Array.from(request.headers.entries()) : [],
                    requestBody: requestBody,
                    timestamp: Date.now()
                  });

                  // Proceed with original fetch
                  return originalFetch.apply(this, arguments);
                }

                // Check for matching intercept rule
                let matchingRule = null;
                window.mcpNetworkInterception.interceptors.forEach((interceptor) => {
                  if (url.toString().match(interceptor.urlPattern)) {
                    matchingRule = interceptor;
                  }
                });

                if (matchingRule) {
                  // Record the intercepted request
                  window.mcpNetworkInterception.records.push({
                    url: url.toString(),
                    method: options?.method || 'GET',
                    requestHeaders: options?.headers || {},
                    requestBody: options?.body || '',
                    intercepted: true,
                    timestamp: Date.now()
                  });

                  // Create mock response body
                  let responseBody = matchingRule.responseBody;
                  if (typeof responseBody === 'object') {
                    responseBody = JSON.stringify(responseBody);
                  }

                  // Create headers
                  const headers = new Headers();
                  headers.append('Content-Type', matchingRule.contentType || 'application/json');

                  // Add any custom headers
                  if (matchingRule.responseHeaders) {
                    Object.keys(matchingRule.responseHeaders).forEach(name => {
                      headers.append(name, matchingRule.responseHeaders[name]);
                    });
                  }

                  // Return mock response
                  return new Response(responseBody, {
                    status: matchingRule.responseCode || 200,
                    statusText: 'OK',
                    headers: headers
                  });
                }

                // If no matching rule, proceed with original fetch
                return originalFetch.apply(this, arguments);
              };

              // Intercept XMLHttpRequest
              XMLHttpRequest.prototype.open = function(method, url, async, user, password) {
                this._mcpMethod = method;
                this._mcpUrl = url;
                this._mcpHeaders = {};

                // Check if this request should be intercepted
                this._mcpShouldIntercept = false;
                this._mcpMatchingRule = null;

                window.mcpNetworkInterception.interceptors.forEach((interceptor) => {
                  if (url.toString().match(interceptor.urlPattern)) {
                    this._mcpShouldIntercept = true;
                    this._mcpMatchingRule = interceptor;
                  }
                });

                // Call original open
                return originalXHROpen.apply(this, arguments);
              };

              // Store request headers
              const originalXHRSetRequestHeader = XMLHttpRequest.prototype.setRequestHeader;
              XMLHttpRequest.prototype.setRequestHeader = function(name, value) {
                if (this._mcpHeaders) {
                  this._mcpHeaders[name] = value;
                }
                return originalXHRSetRequestHeader.apply(this, arguments);
              };

              // Intercept send method
              XMLHttpRequest.prototype.send = function(body) {
                // For monitoring mode, just record the request
                if (window.mcpNetworkInterception.isMonitoring) {
                  window.mcpNetworkInterception.records.push({
                    url: this._mcpUrl,
                    method: this._mcpMethod,
                    requestHeaders: this._mcpHeaders || {},
                    requestBody: body || '',
                    timestamp: Date.now()
                  });

                  // Proceed with original send
                  return originalXHRSend.apply(this, arguments);
                }

                // Check if this request should be intercepted
                if (this._mcpShouldIntercept && this._mcpMatchingRule) {
                  const rule = this._mcpMatchingRule;

                  // Record the intercepted request
                  window.mcpNetworkInterception.records.push({
                    url: this._mcpUrl,
                    method: this._mcpMethod,
                    requestHeaders: this._mcpHeaders || {},
                    requestBody: body || '',
                    intercepted: true,
                    timestamp: Date.now()
                  });

                  // Create mock response
                  let responseBody = rule.responseBody;
                  if (typeof responseBody === 'object') {
                    responseBody = JSON.stringify(responseBody);
                  }

                  // Create a timer to simulate network delay
                  setTimeout(() => {
                    // Set response headers
                    Object.defineProperty(this, 'status', { value: rule.responseCode || 200 });
                    Object.defineProperty(this, 'statusText', { value: 'OK' });
                    Object.defineProperty(this, 'responseText', { value: responseBody });
                    Object.defineProperty(this, 'response', { value: responseBody });

                    // Set default content type
                    this.setRequestHeader('Content-Type', rule.contentType || 'application/json');

                    // Add any custom response headers
                    if (rule.responseHeaders) {
                      Object.keys(rule.responseHeaders).forEach(name => {
                        this.setRequestHeader(name, rule.responseHeaders[name]);
                      });
                    }

                    // Trigger load events
                    const loadEvent = new Event('load');
                    this.dispatchEvent(loadEvent);

                    if (this.onload) {
                      this.onload(loadEvent);
                    }

                    const readyStateChangeEvent = new Event('readystatechange');
                    Object.defineProperty(this, 'readyState', { value: 4 });
                    this.dispatchEvent(readyStateChangeEvent);

                    if (this.onreadystatechange) {
                      this.onreadystatechange(readyStateChangeEvent);
                    }
                  }, 10); // Small delay to simulate network

                  // Don't call original send
                  return;
                }

                // If no interception, proceed with original send
                return originalXHRSend.apply(this, arguments);
              };

              setupMethod = 'monkeyPatch';
            } catch (e) {
              console.error('Failed to set up interception via monkey patching:', e);
            }
          }

          return { setupMethod };
        }

        // Register the intercept rules
        const interceptRules = " & (if interceptRules is missing value or interceptRules is "" then "[]" else interceptRules) & ";

        // Process and store the intercept rules
        if (Array.isArray(interceptRules)) {
          interceptRules.forEach((rule, index) => {
            if (!rule.urlPattern) {
              console.error(`Intercept rule at index ${index} missing urlPattern`);
              return;
            }

            // Convert string patterns to RegExp for more efficient matching
            let pattern = rule.urlPattern;
            if (typeof pattern === 'string') {
              // Escape special regex characters but keep * as wildcard
              pattern = pattern.replace(/[.+?^${}()|[\\]\\/]/g, '\\\\$&')
                              .replace(/\\\\\\*/g, '.*');
              pattern = new RegExp(pattern);
            }

            // Store the rule with processed pattern
            const processedRule = {
              ...rule,
              urlPattern: pattern
            };

            window.mcpNetworkInterception.interceptors.set(index, processedRule);
          });
        }

        // Start the interception with chosen method
        return setupNetworkInterception().then(result => {
          return {
            success: true,
            message: `Network interception set up using ${result.setupMethod}`,
            sessionId: '" & sessionId & "',
            interceptRuleCount: window.mcpNetworkInterception.interceptors.size,
            recordMode: " & isRecordMode & "
          };
        }).catch(error => {
          return {
            error: true,
            message: `Failed to set up network interception: ${error.message}`,
            sessionId: '" & sessionId & "'
          };
        });
      } catch (e) {
        return { 
          error: true, 
          message: e.toString(),
          stack: e.stack
        };
      }
    })();
  "

  -- Execute the script
  tell application "Google Chrome"
    try
      set initResult to execute active tab of front window javascript interceptScript

      -- Check for session ID to determine if we need to wait for results
      if initResult contains sessionId then
        -- Poll for the results with timeout
        set maxAttempts to 30
        set attemptCounter to 0

        -- Create a script to retrieve the current interception status
        set statusScript to "
          (function() {
            if (window.mcpNetworkInterception) {
              return {
                activeSession: window.mcpNetworkInterception.activeSession,
                isMonitoring: window.mcpNetworkInterception.isMonitoring,
                interceptorCount: window.mcpNetworkInterception.interceptors.size,
                recordCount: window.mcpNetworkInterception.records.length,
                records: window.mcpNetworkInterception.records
              };
            } else {
              return { error: true, message: 'Network interception not initialized' };
            }
          })();
        "

        repeat
          delay 0.5
          set attemptCounter to attemptCounter + 1
          set statusCheck to execute active tab of front window javascript statusScript

          -- If we successfully initialized, return the status
          if statusCheck contains "activeSession" and statusCheck does not contain "error" then
            if isRecordMode then
              -- In record mode, we want to return the current status
              return statusCheck
            else
              -- In intercept mode, just return confirmation
              return "{\"success\": true, \"message\": \"Network interception configured successfully\", \"sessionId\": \"" & sessionId & "\"}"
            end if
          end if

          -- Timeout check
          if attemptCounter ≥ maxAttempts then
            return "{\"error\": true, \"message\": \"Timed out waiting for network interception to initialize.\"}"
          end if
        end repeat
      else
        -- Return the immediate result if it doesn't contain session ID (likely an error)
        return initResult
      end if
    on error errMsg
      return "{\"error\": true, \"message\": \"" & my escapeJSString(errMsg) & "\"}"
    end try
  end tell
end interceptNetworkRequests

-- Helper function to escape JavaScript strings
on escapeJSString(theString)
  set resultString to ""
  repeat with i from 1 to length of theString
    set currentChar to character i of theString
    if currentChar is "\"" or currentChar is "\\" then
      set resultString to resultString & "\\" & currentChar
    else if ASCII number of currentChar is 10 then
      set resultString to resultString & "\\n"
    else if ASCII number of currentChar is 13 then
      set resultString to resultString & "\\r"
    else if ASCII number of currentChar is 9 then
      set resultString to resultString & "\\t"
    else
      set resultString to resultString & currentChar
    end if
  end repeat
  return resultString
end escapeJSString

return my interceptNetworkRequests("--MCP_INPUT:interceptRules", "--MCP_INPUT:recordMode")

--MCP_INPUT:profile
--MCP_INPUT:downloadKbps
--MCP_INPUT:uploadKbps
--MCP_INPUT:latencyMs

on configureNetworkThrottling(profileName, downloadKbps, uploadKbps, latencyMs)
  -- Make sure Chrome is running
  tell application "Google Chrome"
    if not running then
      return "error: Google Chrome is not running."
    end if

    if (count of windows) is 0 then
      return "error: No Chrome windows open."
    end if

    if (count of tabs of front window) is 0 then
      return "error: No tabs in front Chrome window."
    end if

    -- Activate Chrome to ensure it's in the foreground
    activate
  end tell

  -- Open DevTools and switch to Network panel
  tell application "System Events"
    tell process "Google Chrome"
      set frontmost to true
      delay 0.3

      -- Check if DevTools is already open
      set devToolsOpen to false
      repeat with w in windows
        if description of w contains "Developer Tools" then
          set devToolsOpen to true
          exit repeat
        end if
      end repeat

      -- Open DevTools if not already open
      if not devToolsOpen then
        key code 34 using {command down, option down} -- Option+Command+I
        delay 0.7
      end if

      -- Switch to Network panel
      key code 45 using {command down, option down} -- Option+Command+N
      delay 0.5
    end tell
  end tell

  -- Determine if using predefined profile or custom settings
  set useCustomProfile to false
  if profileName is missing value or profileName is "" then
    -- If profile not specified but custom values are, use custom profile
    if (downloadKbps is not missing value and downloadKbps is not "") or (uploadKbps is not missing value and uploadKbps is not "") or (latencyMs is not missing value and latencyMs is not "") then
      set useCustomProfile to true
      -- Set defaults for missing parameters
      if downloadKbps is missing value or downloadKbps is "" then set downloadKbps to 500
      if uploadKbps is missing value or uploadKbps is "" then set uploadKbps to 256
      if latencyMs is missing value or latencyMs is "" then set latencyMs to 300
    else
      -- Default to "Fast 3G" if nothing specified
      set profileName to "Fast 3G"
    end if
  end if

  -- Prepare the JavaScript for network throttling configuration
  set throttlingScript to "
    (function() {
      try {
        // Function to ensure we're in a DevTools context
        function ensureDevToolsContext() {
          if (typeof NetworkConditions === 'undefined' && typeof SDK === 'undefined') {
            // We're not in the DevTools context
            // Check if we can find DevTools elements in the DOM
            if (document.querySelector('.network-throttling-selector')) {
              return { 
                uiAvailable: true, 
                programmaticAPI: false 
              };
            }
            return { 
              error: true, 
              message: 'Not in DevTools context and UI elements not found' 
            };
          }
          return { 
            uiAvailable: false, 
            programmaticAPI: true 
          };
        }

        const devToolsCheck = ensureDevToolsContext();

        " & (if useCustomProfile then "
        // Custom throttling profile
        const customProfile = {
          downloadThroughput: " & downloadKbps & " * 1024 / 8, // Convert Kbps to Bytes/s
          uploadThroughput: " & uploadKbps & " * 1024 / 8,
          latency: " & latencyMs & "
        };
        const profileDescription = 'Custom (" & downloadKbps & " Kbps down, " & latencyMs & "ms latency)';
        " else "
        // Predefined throttling profile
        const profileName = '" & my escapeJSString(profileName) & "';
        let predefinedProfile;
        let profileDescription;

        // Define the network conditions for predefined profiles
        switch (profileName.toLowerCase()) {
          case 'offline':
            predefinedProfile = { offline: true, latency: 0, downloadThroughput: 0, uploadThroughput: 0 };
            profileDescription = 'Offline';
            break;
          case 'slow 3g':
            predefinedProfile = { offline: false, latency: 400, downloadThroughput: 400 * 1024 / 8, uploadThroughput: 400 * 1024 / 8 };
            profileDescription = 'Slow 3G (400 Kbps, 400ms RTT)';
            break;
          case 'fast 3g':
            predefinedProfile = { offline: false, latency: 200, downloadThroughput: 1.5 * 1024 * 1024 / 8, uploadThroughput: 750 * 1024 / 8 };
            profileDescription = 'Fast 3G (1.5 Mbps, 200ms RTT)';
            break;
          case 'online':
          case 'no throttling':
          case 'disabled':
            predefinedProfile = { offline: false, latency: 0, downloadThroughput: -1, uploadThroughput: -1 };
            profileDescription = 'Online (No throttling)';
            break;
          default:
            return { error: true, message: 'Unknown predefined profile: ' + profileName };
        }
        ") & "

        // First attempt: Use DevTools API if available
        if (devToolsCheck.programmaticAPI) {
          if (typeof SDK !== 'undefined' && SDK.NetworkManager && SDK.NetworkManager.throttlingManager) {
            // Modern DevTools API approach
            const manager = SDK.NetworkManager.throttlingManager();

            " & (if useCustomProfile then "
            // Apply custom profile
            manager.setCustomConditions(customProfile.latency, customProfile.downloadThroughput, customProfile.uploadThroughput);
            return { success: true, message: 'Applied custom throttling: ' + profileDescription };
            " else "
            // Apply predefined profile
            if (predefinedProfile.offline) {
              manager.setNetworkConditions(SDK.NetworkManager.OfflineConditions);
            } else if (predefinedProfile.downloadThroughput === -1) {
              manager.setNetworkConditions(SDK.NetworkManager.NoThrottlingConditions);
            } else {
              manager.setNetworkConditions(new SDK.NetworkManager.Conditions(
                predefinedProfile.latency,
                predefinedProfile.downloadThroughput,
                predefinedProfile.uploadThroughput,
                false
              ));
            }
            return { success: true, message: 'Applied network profile: ' + profileDescription };
            ") & "
          } else if (typeof NetworkConditions !== 'undefined') {
            // Older DevTools API approach
            const conditions = " & (if useCustomProfile then "
              new NetworkConditions(customProfile.latency, 
                                  customProfile.downloadThroughput, 
                                  customProfile.uploadThroughput);
            " else "
              new NetworkConditions(predefinedProfile.latency, 
                                  predefinedProfile.downloadThroughput, 
                                  predefinedProfile.uploadThroughput, 
                                  predefinedProfile.offline);
            ") & "

            NetworkConditions.setNetworkConditions(conditions);
            return { success: true, message: 'Applied network conditions using legacy API: ' + profileDescription };
          } else if (typeof Mobile !== 'undefined' && typeof Mobile.NetworkManager !== 'undefined') {
            // Alternative DevTools API path
            " & (if useCustomProfile then "
            Mobile.NetworkManager.setNetworkConditions(customProfile.latency, 
                                                   customProfile.downloadThroughput, 
                                                   customProfile.uploadThroughput);
            " else "
            Mobile.NetworkManager.setNetworkConditions(predefinedProfile.latency, 
                                                   predefinedProfile.downloadThroughput, 
                                                   predefinedProfile.uploadThroughput, 
                                                   predefinedProfile.offline);
            ") & "
            return { success: true, message: 'Applied network conditions using Mobile API: ' + profileDescription };
          }
        }

        // Second attempt: UI automation via JavaScript
        if (devToolsCheck.uiAvailable) {
          // Find and click the network throttling dropdown
          const throttlingSelector = document.querySelector('.network-throttling-selector');
          if (throttlingSelector) {
            throttlingSelector.click();

            // Wait for dropdown menu to appear
            setTimeout(() => {
              // Look for the option matching our profile
              const menuItems = document.querySelectorAll('.toolbar-item');
              let found = false;

              for (const item of menuItems) {
                " & (if useCustomProfile then "
                // For custom profile, look for "Custom..." option
                if (item.textContent.includes('Custom')) {
                  item.click();
                  found = true;

                  // Wait for custom dialog
                  setTimeout(() => {
                    // Try to find input fields for custom values
                    const downloadInput = document.querySelector('[aria-label=\"Download\"]');
                    const uploadInput = document.querySelector('[aria-label=\"Upload\"]');
                    const latencyInput = document.querySelector('[aria-label=\"Latency\"]');

                    if (downloadInput && uploadInput && latencyInput) {
                      downloadInput.value = " & downloadKbps & ";
                      uploadInput.value = " & uploadKbps & ";
                      latencyInput.value = " & latencyMs & ";

                      // Find and click the Apply button
                      const buttons = document.querySelectorAll('button');
                      for (const button of buttons) {
                        if (button.textContent.includes('Apply')) {
                          button.click();
                          console.log('Applied custom throttling settings via UI');
                          break;
                        }
                      }
                    }
                  }, 500);
                  break;
                }
                " else "
                // For predefined profile, find matching name
                if (item.textContent.toLowerCase().includes(profileName.toLowerCase())) {
                  item.click();
                  found = true;
                  console.log('Applied network profile via UI: ' + profileDescription);
                  break;
                }
                ") & "
              }

              if (!found) {
                console.error('Profile option not found in UI');
              }
            }, 200);

            return { success: true, message: 'Attempted to set throttling via UI' };
          }
        }

        // Third attempt: Inject a script tag with a workaround
        const scriptTag = document.createElement('script');
        scriptTag.textContent = `
          // Store throttling settings for retrieval
          window.__mcpNetworkThrottling = {
            " & (if useCustomProfile then "
            type: 'custom',
            downloadKbps: " & downloadKbps & ",
            uploadKbps: " & uploadKbps & ",
            latencyMs: " & latencyMs & "
            " else "
            type: 'predefined',
            profile: '" & my escapeJSString(profileName) & "'
            ") & "
          };
          console.log('Network throttling settings stored in window.__mcpNetworkThrottling');
        `;
        document.head.appendChild(scriptTag);

        return { 
          partial: true, 
          message: 'DevTools APIs not available. Instructions: manually select \"" & 
          (if useCustomProfile then "Custom... > " & downloadKbps & "Kbps download, " & uploadKbps & "Kbps upload, " & latencyMs & "ms latency" else profileName) & 
          "\" from the network throttling dropdown in DevTools Network panel.'
        };
      } catch (e) {
        return { error: true, message: e.toString() };
      }
    })();
  "

  -- Execute the throttling script
  tell application "Google Chrome"
    try
      set throttlingResult to execute active tab of front window javascript throttlingScript

      -- Check the result
      if throttlingResult contains "error" then
        return "error: " & throttlingResult
      else if throttlingResult contains "partial" then
        return "partial: " & throttlingResult
      else
        if useCustomProfile then
          return "Successfully configured custom network throttling: " & downloadKbps & " Kbps download, " & uploadKbps & " Kbps upload, " & latencyMs & "ms latency"
        else
          return "Successfully applied network throttling profile: " & profileName
        end if
      end if
    on error errMsg
      return "error: Failed to configure network throttling - " & errMsg
    end try
  end tell
end configureNetworkThrottling

-- Helper function to escape JavaScript strings
on escapeJSString(theString)
  set resultString to ""
  repeat with i from 1 to length of theString
    set currentChar to character i of theString
    if currentChar is "'" or currentChar is "\"" or currentChar is "\\" then
      set resultString to resultString & "\\" & currentChar
    else
      set resultString to resultString & currentChar
    end if
  end repeat
  return resultString
end escapeJSString

return my configureNetworkThrottling("--MCP_INPUT:profile", "--MCP_INPUT:downloadKbps", "--MCP_INPUT:uploadKbps", "--MCP_INPUT:latencyMs")

--MCP_INPUT:duration
--MCP_INPUT:categories
--MCP_INPUT:outputPath
--MCP_INPUT:screencast

on recordPerformanceTrace(recordingDuration, categories, outputPath, includeScreencast)
  -- Set default values
  if recordingDuration is missing value or recordingDuration is "" then
    set recordingDuration to 5 -- Default 5 seconds
  end if

  -- Convert duration to milliseconds
  set durationMs to recordingDuration * 1000

  -- Default categories if not specified
  if categories is missing value or categories is "" then
    set categories to {"loading", "scripting", "rendering", "painting", "network"}
  end if

  -- Default output path if not specified
  if outputPath is missing value or outputPath is "" then
    set userHome to POSIX path of (path to home folder)
    set outputPath to userHome & "Downloads/chrome_performance_trace_" & my getTimestamp() & ".json"
  end if

  -- Default screencast setting
  if includeScreencast is missing value or includeScreencast is "" then
    set includeScreencast to false
  end if

  -- Make sure Chrome is running
  tell application "Google Chrome"
    if not running then
      return "error: Google Chrome is not running."
    end if

    if (count of windows) is 0 then
      return "error: No Chrome windows open."
    end if

    if (count of tabs of front window) is 0 then
      return "error: No tabs in front Chrome window."
    end if

    -- Activate Chrome to ensure it's in the foreground
    activate
  end tell

  -- Open DevTools and switch to Performance panel
  tell application "System Events"
    tell process "Google Chrome"
      set frontmost to true
      delay 0.3

      -- Check if DevTools is already open
      set devToolsOpen to false
      repeat with w in windows
        if description of w contains "Developer Tools" then
          set devToolsOpen to true
          exit repeat
        end if
      end repeat

      -- Open DevTools if not already open
      if not devToolsOpen then
        key code 34 using {command down, option down} -- Option+Command+I
        delay 0.7
      end if

      -- Switch to Performance panel
      key code 35 using {command down, option down} -- Option+Command+P
      delay 0.5
    end tell
  end tell

  -- Generate a unique ID for this recording session
  set sessionId to "mcpPerformanceTrace_" & (random number from 100000 to 999999) as string

  -- Prepare the JavaScript for performance recording
  set recordingScript to "
    (function() {
      try {
        // Create a namespace for our performance recording
        if (!window.mcpPerformance) {
          window.mcpPerformance = {
            activeSession: null,
            recorder: null,
            traceData: null,
            status: 'idle'
          };
        }

        // Clear any existing session with the same ID
        if (window.mcpPerformance.activeSession === '" & sessionId & "') {
          console.log('Stopping previous performance recording session with same ID');
          window.mcpPerformance.activeSession = null;
          window.mcpPerformance.traceData = null;
          window.mcpPerformance.status = 'idle';
        }

        // Set up the new session
        window.mcpPerformance.activeSession = '" & sessionId & "';
        window.mcpPerformance.status = 'initializing';

        // Function to check if we're in DevTools context
        function isInDevToolsContext() {
          return typeof UI !== 'undefined' && typeof SDK !== 'undefined';
        }

        // Function to start recording using Performance API
        async function startRecordingPerformanceAPI() {
          try {
            // Create a PerformanceObserver to capture all entries
            const observer = new PerformanceObserver((list) => {
              for (const entry of list.getEntries()) {
                // Store or process performance entries
                console.log('Performance Entry:', entry.name, entry);
              }
            });

            // Subscribe to various entry types
            observer.observe({ 
              entryTypes: [
                'navigation', 'resource', 'mark', 'measure', 
                'paint', 'longtask', 'layout-shift'
              ] 
            });

            // Mark the start of our custom recording
            performance.mark('mcp-performance-start');

            // Store the observer for cleanup
            window.mcpPerformance.observer = observer;

            return { success: true, method: 'PerformanceAPI' };
          } catch (e) {
            console.error('Failed to start recording using Performance API:', e);
            return { error: true, message: e.toString() };
          }
        }

        // Function to start recording using DevTools Performance panel
        async function startRecordingDevTools() {
          try {
            if (!isInDevToolsContext()) {
              return { error: true, message: 'Not in DevTools context' };
            }

            // Try to access Performance panel components
            if (typeof UI.panels !== 'undefined' && UI.panels.timeline) {
              const performancePanel = UI.panels.timeline;

              // Check if we can access the controller
              if (performancePanel._state && 
                  typeof performancePanel.toggleRecording === 'function') {

                // Configure recording settings
                // Force capture screenshots if enabled
                if (" & includeScreencast & " === true && 
                    typeof performancePanel._captureScreenShotsSetting !== 'undefined') {
                  performancePanel._captureScreenShotsSetting.set(true);
                }

                // Set memory recording
                if (typeof performancePanel._showMemorySetting !== 'undefined') {
                  performancePanel._showMemorySetting.set(true);
                }

                // Start recording
                if (performancePanel._state !== UI.TimelinePanel.State.Recording) {
                  performancePanel.toggleRecording();
                }

                // Store reference to the panel for stopping later
                window.mcpPerformance.recorder = performancePanel;

                return { success: true, method: 'DevToolsPanel' };
              }
            }

            // Try Timeline instead (older DevTools)
            if (typeof Timeline !== 'undefined' && 
                typeof Timeline.TimelinePanel !== 'undefined') {
              const timelinePanel = Timeline.TimelinePanel.instance();

              if (timelinePanel && typeof timelinePanel.toggleRecording === 'function') {
                // Configure settings if possible
                if (" & includeScreencast & " === true && 
                    typeof timelinePanel._captureScreenShotsSetting !== 'undefined') {
                  timelinePanel._captureScreenShotsSetting.set(true);
                }

                // Start recording
                timelinePanel.toggleRecording();

                // Store reference
                window.mcpPerformance.recorder = timelinePanel;

                return { success: true, method: 'TimelinePanel' };
              }
            }

            // Try Performance module (newer DevTools)
            if (typeof Performance !== 'undefined' && 
                typeof Performance.PerformancePanel !== 'undefined') {
              const panel = Performance.PerformancePanel.instance();

              if (panel && typeof panel.toggleRecording === 'function') {
                // Configure settings if possible
                if (" & includeScreencast & " === true && 
                    typeof panel._captureScreenShotsSetting !== 'undefined') {
                  panel._captureScreenShotsSetting.set(true);
                }

                // Start recording
                panel.toggleRecording();

                // Store reference
                window.mcpPerformance.recorder = panel;

                return { success: true, method: 'PerformancePanel' };
              }
            }

            return { error: true, message: 'Could not access Performance panel in DevTools' };
          } catch (e) {
            console.error('Failed to start recording using DevTools panel:', e);
            return { error: true, message: e.toString() };
          }
        }

        // Function to start recording using Chrome Tracing API
        async function startRecordingTracing() {
          try {
            if (typeof chrome !== 'undefined' && chrome.devtools && chrome.debugger) {
              const tabId = chrome.devtools.inspectedWindow.tabId;

              // First detach any existing debugger sessions
              await new Promise(resolve => {
                try {
                  chrome.debugger.detach({tabId}, resolve);
                } catch(e) {
                  resolve();
                }
              });

              // Attach debugger
              await new Promise((resolve, reject) => {
                chrome.debugger.attach({tabId}, '1.3', result => {
                  if (chrome.runtime.lastError) {
                    reject(chrome.runtime.lastError);
                  } else {
                    resolve();
                  }
                });
              });

              // Convert input categories to Chrome's format
              const categoryObj = {};
              const requestedCategories = " & my convertListToJSArray(categories) & ";

              const categoryMap = {
                'loading': ['loading', 'parseHTML', 'resourceLoading'],
                'scripting': ['javaScript', 'parseHTML', 'scriptStreaming'],
                'rendering': ['rendering', 'layout', 'compositing'],
                'painting': ['painting', 'rasterization', 'gpu'],
                'network': ['network', 'netlog', 'loading'],
                'memory': ['memory'],
                'timeline': ['devtools.timeline'],
                'input': ['input', 'evdev']
              };

              // Add specified categories
              for (const category of requestedCategories) {
                if (categoryMap[category]) {
                  for (const detail of categoryMap[category]) {
                    categoryObj[detail] = true;
                  }
                }
              }

              // Always include these
              categoryObj['disabled-by-default-devtools.timeline'] = true;

              // Add screenshots if requested
              if (" & includeScreencast & ") {
                categoryObj['disabled-by-default-devtools.screenshot'] = true;
              }

              // Start tracing
              await new Promise((resolve, reject) => {
                chrome.debugger.sendCommand({tabId}, 'Tracing.start', {
                  categories: Object.keys(categoryObj).join(','),
                  options: 'sampling-frequency=10000',
                  transferMode: 'ReturnAsStream',
                  bufferUsageReportingInterval: 500
                }, result => {
                  if (chrome.runtime.lastError) {
                    reject(chrome.runtime.lastError);
                  } else {
                    resolve();
                  }
                });
              });

              // Store reference to the debugger
              window.mcpPerformance.tracer = {
                tabId: tabId
              };

              return { success: true, method: 'ChromeTracing' };
            }

            return { error: true, message: 'Chrome Tracing API not available' };
          } catch (e) {
            console.error('Failed to start recording using Chrome Tracing:', e);
            return { error: true, message: e.toString() };
          }
        }

        // Try each method in sequence until one works
        async function startRecording() {
          let result = null;

          // First try DevTools Performance Panel
          result = await startRecordingDevTools();
          if (result && result.success) {
            window.mcpPerformance.recordingMethod = result.method;
            window.mcpPerformance.status = 'recording';
            return result;
          }

          // Then try Chrome Tracing API
          result = await startRecordingTracing();
          if (result && result.success) {
            window.mcpPerformance.recordingMethod = result.method;
            window.mcpPerformance.status = 'recording';
            return result;
          }

          // Finally fall back to Performance API
          result = await startRecordingPerformanceAPI();
          if (result && result.success) {
            window.mcpPerformance.recordingMethod = result.method;
            window.mcpPerformance.status = 'recording';
            return result;
          }

          // If all methods failed
          return {
            error: true,
            message: 'Failed to start performance recording with any method'
          };
        }

        // Start the recording
        return startRecording().then(result => {
          if (result.success) {
            // Setup automatic stop after duration
            window.mcpPerformance.stopTimer = setTimeout(() => {
              // Call stop function after the specified duration
              stopRecording();
            }, " & durationMs & ");

            return {
              success: true,
              message: `Started performance recording using ${result.method}`,
              sessionId: '" & sessionId & "',
              status: 'recording',
              duration: " & recordingDuration & ",
              categories: " & my convertListToJSArray(categories) & "
            };
          } else {
            return result;
          }
        });

        // This will be called automatically by the timer
        function stopRecording() {
          return (async () => {
            try {
              let traceData = null;
              const method = window.mcpPerformance.recordingMethod;

              // Mark the end of recording
              performance.mark('mcp-performance-end');
              performance.measure('mcp-performance-duration', 
                                 'mcp-performance-start', 
                                 'mcp-performance-end');

              switch (method) {
                case 'DevToolsPanel':
                case 'TimelinePanel':
                case 'PerformancePanel':
                  if (window.mcpPerformance.recorder) {
                    // Stop recording if it's still active
                    const recorder = window.mcpPerformance.recorder;

                    if (typeof recorder.toggleRecording === 'function') {
                      recorder.toggleRecording();
                    }

                    // Try to get the trace data
                    if (typeof recorder.getDataFileForDownload === 'function') {
                      // Get the trace data file
                      const dataFile = await new Promise(resolve => {
                        recorder.getDataFileForDownload(resolve);
                      });

                      if (dataFile) {
                        traceData = dataFile;
                      }
                    } else if (recorder._model && 
                               typeof recorder._model.saveToFile === 'function') {
                      // Try to access the model's save function
                      const modelData = await new Promise(resolve => {
                        recorder._model.saveToFile(resolve);
                      });

                      if (modelData) {
                        traceData = modelData;
                      }
                    }
                  }
                  break;

                case 'ChromeTracing':
                  if (window.mcpPerformance.tracer) {
                    const tabId = window.mcpPerformance.tracer.tabId;

                    // Stop tracing
                    await new Promise((resolve, reject) => {
                      chrome.debugger.sendCommand({tabId}, 'Tracing.end', {}, result => {
                        if (chrome.runtime.lastError) {
                          reject(chrome.runtime.lastError);
                        } else {
                          resolve();
                        }
                      });
                    });

                    // Get the trace data
                    // This is complex with streams, simplifying for demo
                    traceData = { message: 'Trace data available via chrome.debugger' };
                  }
                  break;

                case 'PerformanceAPI':
                  // Collect data from Performance API
                  const performanceEntries = performance.getEntries();
                  const measures = performance.getEntriesByType('measure')
                    .filter(m => m.name === 'mcp-performance-duration');

                  traceData = {
                    entries: performanceEntries,
                    duration: measures.length > 0 ? measures[0].duration : 0
                  };

                  // Clean up observer
                  if (window.mcpPerformance.observer) {
                    window.mcpPerformance.observer.disconnect();
                  }
                  break;
              }

              // Store the trace data
              window.mcpPerformance.traceData = traceData;
              window.mcpPerformance.status = 'completed';

              // Clean up timer
              if (window.mcpPerformance.stopTimer) {
                clearTimeout(window.mcpPerformance.stopTimer);
              }

              // Signal that recording is complete
              console.log('Performance recording complete');

              // Try to save the file if we have data
              if (traceData) {
                try {
                  // Create a download link for the trace
                  const jsonData = JSON.stringify(traceData);
                  const blob = new Blob([jsonData], {type: 'application/json'});
                  const url = URL.createObjectURL(blob);

                  // Create a link element
                  const a = document.createElement('a');
                  a.style.display = 'none';
                  a.href = url;
                  a.download = 'performance_trace.json';

                  // Add to document and trigger download
                  document.body.appendChild(a);
                  a.click();

                  // Clean up
                  URL.revokeObjectURL(url);
                  document.body.removeChild(a);
                } catch (e) {
                  console.error('Failed to save trace data:', e);
                }
              }

              return {
                success: true,
                message: 'Performance recording completed',
                method: method,
                sessionId: '" & sessionId & "',
                hasTraceData: !!traceData
              };
            } catch (e) {
              console.error('Error stopping performance recording:', e);
              return {
                error: true,
                message: `Error stopping performance recording: ${e.toString()}`
              };
            }
          })();
        }
      } catch (e) {
        return { 
          error: true, 
          message: e.toString(),
          stack: e.stack
        };
      }
    })();
  "

  -- Execute the script to start recording
  tell application "Google Chrome"
    try
      set startResult to execute active tab of front window javascript recordingScript

      -- If the recording started successfully, wait for it to complete
      if startResult contains "success" and startResult contains sessionId then
        -- Show a message to the user that recording is in progress
        set progressMessage to "Recording performance trace for " & recordingDuration & " seconds... Please do not switch tabs or close DevTools."

        -- Calculate the end time for the recording
        set endTime to (current date) + recordingDuration

        -- Wait until the recording is complete
        repeat until (current date) > endTime
          delay 0.5
        end repeat

        -- Create a script to check the recording status
        set statusScript to "
          (function() {
            if (window.mcpPerformance) {
              return {
                status: window.mcpPerformance.status,
                sessionId: window.mcpPerformance.activeSession,
                traceData: window.mcpPerformance.traceData ? true : false
              };
            } else {
              return { error: true, message: 'Performance recording not initialized' };
            }
          })();
        "

        -- Wait a bit more to ensure everything is properly saved
        delay 1

        -- Check if the recording completed successfully
        set statusResult to execute active tab of front window javascript statusScript

        -- If the recording has trace data, save it to the specified file
        if statusResult contains "traceData\":true" then
          -- Create a script to get and save the trace data
          set saveScript to "
            (function() {
              if (window.mcpPerformance && window.mcpPerformance.traceData) {
                try {
                  const traceData = window.mcpPerformance.traceData;

                  // For saving to server-side file, we need to convert to JSON string
                  return JSON.stringify(traceData);
                } catch (e) {
                  return { error: true, message: `Failed to serialize trace data: ${e.toString()}` };
                }
              } else {
                return { error: true, message: 'No trace data available' };
              }
            })();
          "

          -- Get the trace data as JSON
          set traceDataJSON to execute active tab of front window javascript saveScript

          -- Save to the specified file
          try
            do shell script "echo " & quoted form of traceDataJSON & " > " & quoted form of outputPath

            return "Performance trace recorded and saved to: " & outputPath
          on error errMsg
            return "Performance trace recorded but failed to save to file: " & errMsg
          end try
        else
          return "Performance trace recording completed, but no trace data was captured. This may be due to DevTools API restrictions."
        end if
      else
        -- Return the error from starting the recording
        return startResult
      end if
    on error errMsg
      return "error: Failed to record performance trace - " & errMsg
    end try
  end tell
end recordPerformanceTrace

-- Helper function to get formatted timestamp
on getTimestamp()
  set currentDate to current date
  set y to year of currentDate as string
  set m to month of currentDate as integer
  if m < 10 then set m to "0" & m
  set d to day of currentDate as integer
  if d < 10 then set d to "0" & d
  set h to hours of currentDate as integer
  if h < 10 then set h to "0" & h
  set min to minutes of currentDate as integer
  if min < 10 then set min to "0" & min
  set s to seconds of currentDate as integer
  if s < 10 then set s to "0" & s

  return y & m & d & "_" & h & min & s
end getTimestamp

-- Helper function to convert AppleScript list to JavaScript array
on convertListToJSArray(theList)
  set jsArray to "["

  if class of theList is string then
    -- If it's a string, interpret as comma-separated values
    set AppleScript's text item delimiters to ","
    set listItems to text items of theList
    set AppleScript's text item delimiters to ""
  else
    set listItems to theList
  end if

  repeat with i from 1 to count of listItems
    set thisItem to item i of listItems

    -- Trim whitespace
    set thisItem to do shell script "echo " & quoted form of thisItem & " | xargs"

    -- Handle strings with quotes
    set jsArray to jsArray & "\"" & thisItem & "\""

    if i < count of listItems then
      set jsArray to jsArray & ", "
    end if
  end repeat

  set jsArray to jsArray & "]"
  return jsArray
end convertListToJSArray

return my recordPerformanceTrace("--MCP_INPUT:duration", "--MCP_INPUT:categories", "--MCP_INPUT:outputPath", "--MCP_INPUT:screencast")

--MCP_INPUT:tests
--MCP_INPUT:reportPath
--MCP_INPUT:headless

on runChromeTests(testCases, reportPath, headlessMode)
  -- Set default values
  if testCases is missing value or testCases is "" then
    return "error: No test cases provided. Please specify at least one test case."
  end if

  if headlessMode is missing value or headlessMode is "" then
    set headlessMode to false
  end if

  -- Default report path if not specified
  if reportPath is missing value or reportPath is "" then
    set userHome to POSIX path of (path to home folder)
    set reportPath to userHome & "Downloads/chrome_test_report_" & my getTimestamp() & ".json"
  end if

  -- Check if we should use headless mode
  if headlessMode then
    -- Launch Chrome in headless mode
    return my runHeadlessTests(testCases, reportPath)
  end if

  -- Make sure Chrome is running for non-headless tests
  tell application "Google Chrome"
    if not running then
      return "error: Google Chrome is not running. Please start Chrome or use headless mode."
    end if

    if (count of windows) is 0 then
      return "error: No Chrome windows open."
    end if

    if (count of tabs of front window) is 0 then
      return "error: No tabs in front Chrome window."
    end if

    -- Activate Chrome to ensure it's in the foreground
    activate
  end tell

  -- Generate a unique ID for this test session
  set sessionId to "mcpTestRunner_" & (random number from 100000 to 999999) as string

  -- Prepare the JavaScript for test execution
  set runnerScript to "
    (function() {
      try {
        // Create namespace for our test runner
        if (!window.mcpTestRunner) {
          window.mcpTestRunner = {
            activeSession: null,
            testCases: [],
            results: [],
            status: 'idle',
            currentTestIndex: -1
          };
        }

        // Clear any existing session with the same ID
        if (window.mcpTestRunner.activeSession === '" & sessionId & "') {
          console.log('Stopping previous test session with same ID');
          window.mcpTestRunner.activeSession = null;
          window.mcpTestRunner.testCases = [];
          window.mcpTestRunner.results = [];
          window.mcpTestRunner.status = 'idle';
          window.mcpTestRunner.currentTestIndex = -1;
        }

        // Set up the new session
        window.mcpTestRunner.activeSession = '" & sessionId & "';
        window.mcpTestRunner.status = 'initializing';
        window.mcpTestRunner.testCases = " & testCases & ";
        window.mcpTestRunner.currentTestIndex = -1;

        /* ----- Test Assertion Utilities ----- */

        // Wait for a selector to appear in the DOM
        async function waitForSelector(selector, timeout = 10000) {
          const startTime = Date.now();

          while (Date.now() - startTime < timeout) {
            const element = document.querySelector(selector);
            if (element) {
              return element;
            }

            // Wait a bit before trying again
            await new Promise(resolve => setTimeout(resolve, 100));
          }

          throw new Error(`Timeout waiting for selector: ${selector}`);
        }

        // Wait for navigation to complete
        async function waitForNavigation(timeout = 30000) {
          // If document is already complete, we're done
          if (document.readyState === 'complete') {
            return;
          }

          // Otherwise wait for the 'load' event
          return new Promise((resolve, reject) => {
            const timeoutId = setTimeout(() => {
              reject(new Error('Navigation timeout'));
            }, timeout);

            window.addEventListener('load', () => {
              clearTimeout(timeoutId);
              // Add a small delay after load for scripts to execute
              setTimeout(resolve, 500);
            }, { once: true });
          });
        }

        // Take a screenshot using canvas
        async function takeScreenshot() {
          // Create a canvas element
          const canvas = document.createElement('canvas');
          canvas.width = window.innerWidth;
          canvas.height = window.innerHeight;

          // Get the canvas context and draw the current viewport
          const context = canvas.getContext('2d');
          context.drawImage(document, 0, 0, window.innerWidth, window.innerHeight);

          // Convert to data URL and return
          return canvas.toDataURL('image/png');
        }

        // Get stacked element path for error messages
        function getElementPath(element) {
          if (!element) return 'Element not found';

          let path = [];
          let currentElement = element;

          while (currentElement && currentElement.tagName) {
            let identifier = currentElement.tagName.toLowerCase();

            if (currentElement.id) {
              identifier += `#${currentElement.id}`;
            } else if (currentElement.className) {
              const classes = currentElement.className.split(' ')
                .filter(c => c)
                .map(c => `.${c}`)
                .join('');
              identifier += classes;
            }

            path.unshift(identifier);
            currentElement = currentElement.parentElement;

            // Limit path depth
            if (path.length > 5) break;
          }

          return path.join(' > ');
        }

        // Check a specific assertion
        async function checkAssertion(assertion, context = document) {
          const result = {
            type: assertion.type,
            selector: assertion.selector,
            expected: assertion.expected,
            actual: null,
            success: false,
            error: null
          };

          try {
            let element = null;

            // If a selector is provided, find the element
            if (assertion.selector) {
              element = await waitForSelector(assertion.selector, assertion.timeout || 10000);
              if (!element) {
                throw new Error(`Element not found: ${assertion.selector}`);
              }

              // Add element path to the result for debugging
              result.elementPath = getElementPath(element);
            }

            // Check different assertion types
            switch (assertion.type) {
              case 'text':
              case 'textContent':
                result.actual = element.textContent.trim();
                result.success = result.actual === assertion.expected;
                break;

              case 'innerHTML':
                result.actual = element.innerHTML.trim();
                result.success = result.actual === assertion.expected;
                break;

              case 'value':
                result.actual = element.value;
                result.success = result.actual === assertion.expected;
                break;

              case 'attribute':
                if (!assertion.attribute) {
                  throw new Error('attribute name is required for attribute assertions');
                }
                result.attribute = assertion.attribute;
                result.actual = element.getAttribute(assertion.attribute);
                result.success = result.actual === assertion.expected;
                break;

              case 'exists':
                result.actual = !!element;
                result.success = result.actual === (assertion.expected !== false);
                break;

              case 'visible':
                const style = window.getComputedStyle(element);
                result.actual = style.display !== 'none' && 
                                style.visibility !== 'hidden' && 
                                style.opacity !== '0';
                result.success = result.actual === (assertion.expected !== false);
                break;

              case 'count':
                const elements = context.querySelectorAll(assertion.selector);
                result.actual = elements.length;
                result.success = result.actual === assertion.expected;
                break;

              case 'url':
                result.actual = window.location.href;

                if (assertion.contains) {
                  result.success = result.actual.includes(assertion.expected);
                } else {
                  result.success = result.actual === assertion.expected;
                }
                break;

              case 'title':
                result.actual = document.title;
                result.success = result.actual === assertion.expected;
                break;

              case 'jsExpression':
                if (!assertion.expression) {
                  throw new Error('expression is required for jsExpression assertions');
                }

                // Safely evaluate the expression
                const expressionFn = new Function('return ' + assertion.expression);
                result.actual = expressionFn();
                result.success = result.actual === assertion.expected;
                break;

              case 'cookie':
                if (!assertion.name) {
                  throw new Error('cookie name is required for cookie assertions');
                }

                const cookies = document.cookie.split(';')
                  .map(c => c.trim().split('='))
                  .reduce((acc, [name, value]) => {
                    acc[name] = value;
                    return acc;
                  }, {});

                result.actual = cookies[assertion.name];
                result.success = result.actual === assertion.expected;
                break;

              case 'console':
                // This requires special handling as we need to monitor console
                // For now, just report that it can't be checked directly
                result.error = 'Console assertions require monitoring before the test runs';
                result.success = false;
                break;

              default:
                result.error = `Unknown assertion type: ${assertion.type}`;
                result.success = false;
            }
          } catch (error) {
            result.success = false;
            result.error = error.message;
          }

          return result;
        }

        /* ----- Test Execution ----- */

        // Execute a single test case
        async function executeTest(test, index) {
          const result = {
            name: test.name || `Test ${index + 1}`,
            url: test.url,
            startTime: Date.now(),
            endTime: null,
            duration: 0,
            status: 'running',
            assertions: [],
            screenshot: null,
            error: null
          };

          try {
            // Navigate to the test URL if provided
            if (test.url) {
              // Record if we're on the same domain or cross-origin
              const currentUrl = window.location.href;
              const targetUrl = test.url;
              const isSameDomain = currentUrl.startsWith(window.location.origin) && 
                                 targetUrl.startsWith(window.location.origin);

              // Navigate and wait for page to load
              window.location.href = test.url;

              // If cross-origin, we can't really wait properly
              if (isSameDomain) {
                await waitForNavigation();
              } else {
                // For cross-origin, just wait a bit
                await new Promise(resolve => setTimeout(resolve, 5000));
              }
            }

            // Wait for page readiness if specified
            if (test.readySelector) {
              await waitForSelector(test.readySelector, test.timeout || 30000);
            } else if (test.readyState) {
              // If specific ready state is required
              if (test.readyState === 'networkIdle') {
                // Wait for network to be idle - approximate by waiting
                await new Promise(resolve => setTimeout(resolve, 2000));
              }
            }

            // Run any setup steps
            if (test.setup) {
              for (const step of test.setup) {
                switch (step.action) {
                  case 'click':
                    const clickEl = await waitForSelector(step.selector, step.timeout || 10000);
                    clickEl.click();
                    // Wait a bit for the click to take effect
                    await new Promise(resolve => setTimeout(resolve, 1000));
                    break;

                  case 'type':
                    const inputEl = await waitForSelector(step.selector, step.timeout || 10000);
                    inputEl.value = step.text;
                    inputEl.dispatchEvent(new Event('input', { bubbles: true }));
                    break;

                  case 'wait':
                    await new Promise(resolve => setTimeout(resolve, step.duration || 1000));
                    break;

                  case 'executeJs':
                    if (step.code) {
                      // Execute JS directly in the page context
                      const execFn = new Function(step.code);
                      execFn();
                    }
                    break;

                  default:
                    console.warn(`Unknown setup action: ${step.action}`);
                }
              }
            }

            // Run assertions
            if (test.assertions && test.assertions.length > 0) {
              for (const assertion of test.assertions) {
                const assertionResult = await checkAssertion(assertion);
                result.assertions.push(assertionResult);

                // If this is a critical assertion and it failed, stop the test
                if (assertion.critical && !assertionResult.success) {
                  throw new Error(`Critical assertion failed: ${assertionResult.error || 'Expected ' + assertion.expected + ' but got ' + assertionResult.actual}`);
                }
              }
            }

            // Take screenshot if requested
            if (test.screenshot) {
              result.screenshot = await takeScreenshot();
            }

            // Mark test as passed
            result.status = 'passed';
          } catch (error) {
            // Mark test as failed
            result.status = 'failed';
            result.error = error.message;

            // Take failure screenshot if enabled
            if (test.screenshotOnFailure) {
              result.screenshot = await takeScreenshot();
            }
          } finally {
            // Record end time and duration
            result.endTime = Date.now();
            result.duration = result.endTime - result.startTime;
          }

          return result;
        }

        // Execute all test cases sequentially
        async function executeAllTests() {
          const results = [];
          const startTime = Date.now();

          try {
            for (let i = 0; i < window.mcpTestRunner.testCases.length; i++) {
              window.mcpTestRunner.currentTestIndex = i;
              const test = window.mcpTestRunner.testCases[i];

              // Execute the test and get results
              const result = await executeTest(test, i);
              results.push(result);

              // If one test fails and stopOnFailure is true, stop testing
              if (result.status === 'failed' && test.stopOnFailure) {
                break;
              }
            }

            // Compile overall results
            const endTime = Date.now();
            const passed = results.filter(r => r.status === 'passed').length;
            const failed = results.filter(r => r.status === 'failed').length;

            const finalResults = {
              sessionId: window.mcpTestRunner.activeSession,
              startTime: startTime,
              endTime: endTime,
              duration: endTime - startTime,
              total: results.length,
              passed: passed,
              failed: failed,
              status: failed === 0 ? 'passed' : 'failed',
              tests: results
            };

            // Store results
            window.mcpTestRunner.results = finalResults;
            window.mcpTestRunner.status = 'completed';

            return finalResults;
          } catch (error) {
            // Handle unexpected errors in the test framework
            const endTime = Date.now();

            const errorResults = {
              sessionId: window.mcpTestRunner.activeSession,
              startTime: startTime,
              endTime: endTime,
              duration: endTime - startTime,
              total: window.mcpTestRunner.testCases.length,
              passed: results.filter(r => r.status === 'passed').length,
              failed: results.length - results.filter(r => r.status === 'passed').length + 1,
              status: 'error',
              error: error.message,
              stack: error.stack,
              tests: results
            };

            // Store results even with error
            window.mcpTestRunner.results = errorResults;
            window.mcpTestRunner.status = 'error';

            return errorResults;
          }
        }

        // Start the test execution
        window.mcpTestRunner.executionPromise = executeAllTests();

        // Return immediately with execution started status
        return {
          status: 'executing',
          message: 'Test execution started',
          testCount: window.mcpTestRunner.testCases.length,
          sessionId: window.mcpTestRunner.activeSession
        };
      } catch (e) {
        return { 
          error: true, 
          message: e.toString(),
          stack: e.stack
        };
      }
    })();
  "

  -- Execute the script to start the tests
  tell application "Google Chrome"
    try
      set startResult to execute active tab of front window javascript runnerScript

      -- If the tests started successfully, wait for them to complete
      if startResult contains "executing" and startResult contains sessionId then
        -- Show a message that tests are running
        set testCount to do shell script "echo " & quoted form of startResult & " | grep -o '\"testCount\":[0-9]*' | cut -d':' -f2"
        set progressMessage to "Running " & testCount & " tests... Please do not switch tabs or close Chrome."

        -- Create a script to check the test status
        set statusScript to "
          (function() {
            if (window.mcpTestRunner) {
              return {
                status: window.mcpTestRunner.status,
                sessionId: window.mcpTestRunner.activeSession,
                currentTest: window.mcpTestRunner.currentTestIndex,
                totalTests: window.mcpTestRunner.testCases ? window.mcpTestRunner.testCases.length : 0,
                hasResults: !!window.mcpTestRunner.results && window.mcpTestRunner.results.tests
              };
            } else {
              return { error: true, message: 'Test runner not initialized' };
            }
          })();
        "

        -- Poll for the status with timeout
        set maxAttempts to 300 -- 2.5 minutes max wait time
        set attemptCounter to 0

        repeat
          delay 0.5
          set attemptCounter to attemptCounter + 1
          set statusCheck to execute active tab of front window javascript statusScript

          -- If the tests completed, get the results
          if statusCheck contains "\"status\":\"completed\"" or statusCheck contains "\"status\":\"error\"" then
            -- Get the full test results
            set resultsScript to "
              (function() {
                if (window.mcpTestRunner && window.mcpTestRunner.results) {
                  // Clone results and remove screenshots to keep response size manageable
                  const results = JSON.parse(JSON.stringify(window.mcpTestRunner.results));

                  // Store screenshot data separately
                  const screenshots = {};

                  // Extract screenshots
                  if (results.tests) {
                    results.tests.forEach((test, index) => {
                      if (test.screenshot) {
                        screenshots[`test_${index}`] = test.screenshot;
                        test.screenshot = `[Screenshot data stored separately as test_${index}]`;
                      }
                    });
                  }

                  // Return complete results
                  return {
                    results: results,
                    screenshots: screenshots,
                    screenshotCount: Object.keys(screenshots).length
                  };
                } else {
                  return { error: true, message: 'No test results available' };
                }
              })();
            "

            -- Get the results
            set resultsData to execute active tab of front window javascript resultsScript

            -- Try to save the report to file
            try
              -- Extract just the results part for the report
              set reportScript to "
                (function() {
                  if (window.mcpTestRunner && window.mcpTestRunner.results) {
                    return JSON.stringify(window.mcpTestRunner.results, null, 2);
                  } else {
                    return JSON.stringify({ error: 'No test results available' });
                  }
                })();
              "

              set reportJSON to execute active tab of front window javascript reportScript

              -- Save to the specified file
              do shell script "echo " & quoted form of reportJSON & " > " & quoted form of reportPath
            on error errMsg
              return "{\"error\": true, \"message\": \"Tests completed but failed to save report: " & my escapeJSString(errMsg) & "\"}"
            end try

            -- Return a success message or the results
            return resultsData
          end if

          -- Handle status updates
          if statusCheck contains "\"currentTest\":" then
            -- Extract current test number
            set currentTestNumString to do shell script "echo " & quoted form of statusCheck & " | grep -o '\"currentTest\":[0-9]*' | cut -d':' -f2"
            set currentTestNum to currentTestNumString as integer

            -- TODO: Could use this to update progress indicator if needed
          end if

          -- Timeout check
          if attemptCounter ≥ maxAttempts then
            return "{\"error\": true, \"message\": \"Timed out waiting for tests to complete.\"}"
          end if
        end repeat
      else
        -- Return the error from starting the tests
        return startResult
      end if
    on error errMsg
      return "{\"error\": true, \"message\": \"" & my escapeJSString(errMsg) & "\"}"
    end try
  end tell
end runChromeTests

