-- Helper function to get formatted timestamp
on getTimestamp()
  set currentDate to current date
  set y to year of currentDate as string
  set m to month of currentDate as integer
  if m < 10 then set m to "0" & m
  set d to day of currentDate as integer
  if d < 10 then set d to "0" & d
  set h to hours of currentDate as integer
  if h < 10 then set h to "0" & h
  set min to minutes of currentDate as integer
  if min < 10 then set min to "0" & min
  set s to seconds of currentDate as integer
  if s < 10 then set s to "0" & s

  return y & m & d & "_" & h & min & s
end getTimestamp

-- Helper function to escape JavaScript strings
on escapeJSString(theString)
  set resultString to ""
  repeat with i from 1 to length of theString
    set currentChar to character i of theString
    if currentChar is "\"" or currentChar is "\\" then
      set resultString to resultString & "\\" & currentChar
    else if ASCII number of currentChar is 10 then
      set resultString to resultString & "\\n"
    else if ASCII number of currentChar is 13 then
      set resultString to resultString & "\\r"
    else if ASCII number of currentChar is 9 then
      set resultString to resultString & "\\t"
    else
      set resultString to resultString & currentChar
    end if
  end repeat
  return resultString
end escapeJSString

return my runChromeTests("--MCP_INPUT:tests", "--MCP_INPUT:reportPath", "--MCP_INPUT:headless")

on run argv
	-- Parse arguments with default values
	set action to "list"
	set css_selector to "document"
	set event_type to ""
	set options_json to "{}"
	set monitor_duration to 10

	-- Process arguments if provided
	if (count of argv) ≥ 1 then
		if item 1 of argv is not "" then
			set action to item 1 of argv
		end if
	end if

	if (count of argv) ≥ 2 then
		if item 2 of argv is not "" then
			set css_selector to item 2 of argv
		end if
	end if

	if (count of argv) ≥ 3 then
		if item 3 of argv is not "" then
			set event_type to item 3 of argv
		end if
	end if

	if (count of argv) ≥ 4 then
		if item 4 of argv is not "" then
			set options_json to item 4 of argv
		end if
	end if

	if (count of argv) ≥ 5 then
		if item 5 of argv is not "" then
			try
				set monitor_duration to item 5 of argv as number
			on error
				set monitor_duration to 10
			end try
		end if
	end if

	-- Check if Safari is running
	tell application "System Events"
		set safariRunning to (exists process "Safari")
	end tell

	if not safariRunning then
		return "{\"error\": \"Safari is not running. Please open Safari and try again.\"}"
	end if

	tell application "Safari"
		set current_tab to current tab of window 1

		-- Perform the requested action
		if action is "list" then
			set result to my listEventListeners(current_tab, css_selector, event_type)
		else if action is "add" then
			set result to my addEventListeners(current_tab, css_selector, event_type, options_json)
		else if action is "remove" then
			set result to my removeEventListeners(current_tab, css_selector, event_type)
		else if action is "monitor" then
			set result to my monitorEvents(current_tab, css_selector, event_type, monitor_duration)
		else if action is "trigger" then
			set result to my triggerEvent(current_tab, css_selector, event_type, options_json)
		else if action is "analyze" then
			set result to my analyzeEventPropagation(current_tab, css_selector, event_type)
		else
			set result to "{\"error\": \"Invalid action. Use 'list', 'add', 'remove', 'monitor', 'trigger', or 'analyze'.\"}"
		end if

		return result
	end tell
end run

-- List all event listeners on the page or specific elements
on listEventListeners(tab_ref, selector, event_type)
	tell application "Safari"
		set js_result to do JavaScript "
			(function() {
				// Helper function to detect jQuery event handlers
				function getJQueryEvents(element) {
					if (window.jQuery && element.jquery) {
						return jQuery._data(element[0], 'events') || {};
					} else if (window.jQuery && jQuery._data) {
						return jQuery._data(element, 'events') || {};
					}
					return null;
				}

				// Helper function to get event listeners
				function getElementListeners(element) {
					if (!element) return [];

					let listeners = [];

					// Check for jQuery events first
					const jQueryEvents = getJQueryEvents(element);
					if (jQueryEvents) {
						for (const [eventType, handlers] of Object.entries(jQueryEvents)) {
							handlers.forEach(handler => {
								listeners.push({
									type: eventType,
									handler: 'jQuery handler',
									source: 'jQuery',
									element: element.tagName || 'DOCUMENT'
								});
							});
						}
					}

					// For standard DOM listeners, we can't access them directly
					// We can infer some information based on element attributes
					for (const attr of element.attributes || []) {
						if (attr.name.startsWith('on')) {
							const eventType = attr.name.slice(2);
							listeners.push({
								type: eventType,
								handler: 'Inline handler',
								source: 'HTML attribute',
								element: element.tagName || 'DOCUMENT'
							});
						}
					}

					// Add note about listener limitations
					if (listeners.length === 0) {
						if (element.onclick || element.onmouseover || element.onkeydown) {
							listeners.push({
								type: 'unknown',
								handler: 'DOM property handler',
								source: 'DOM property (e.g. element.onclick)',
								element: element.tagName || 'DOCUMENT'
							});
						}
					}

					return listeners;
				}

				let elements = [];
				let eventFilter = '" & event_type & "';

				// Parse selector
				try {
					if ('" & selector & "' === 'document') {
						elements = [document];
					} else {
						elements = Array.from(document.querySelectorAll('" & selector & "'));
					}
				} catch (error) {
					return JSON.stringify({
						error: 'Invalid selector: ' + error.message
					});
				}

				// Collect all event listeners
				let result = {
					count: 0,
					listeners: []
				};

				// Find inline events in HTML
				const allTags = document.querySelectorAll('*');
				const inlineEvents = [];
				for (const elem of allTags) {
					for (const attr of elem.attributes) {
						if (attr.name.startsWith('on')) {
							const eventType = attr.name.slice(2);
							if (!eventFilter || eventType === eventFilter) {
								inlineEvents.push({
									type: eventType,
									element: elem.tagName,
									id: elem.id || null,
									class: elem.className || null,
									handler: 'Inline HTML attribute',
									source: 'HTML'
								});
							}
						}
					}
				}

				// Find script tag event listeners
				const scripts = document.querySelectorAll('script');
				const scriptEvents = [];
				const eventRegex = /addEventListener\\(['\"]([^'\"]+)['\"]|\\.(on\\w+)\\s*=/g;
				for (const script of scripts) {
					if (!script.textContent) continue;

					let match;
					while ((match = eventRegex.exec(script.textContent)) !== null) {
						const eventType = match[1] || (match[2] && match[2].slice(2));
						if (!eventFilter || eventType === eventFilter) {
							scriptEvents.push({
								type: eventType,
								handler: 'Script handler',
								source: 'Script tag'
							});
						}
					}
				}

				// Process selected elements
				elements.forEach(element => {
					const elementListeners = getElementListeners(element);
					if (eventFilter) {
						elementListeners.filter(l => l.type === eventFilter).forEach(listener => {
							result.listeners.push(listener);
						});
					} else {
						elementListeners.forEach(listener => {
							result.listeners.push(listener);
						});
					}
				});

				// Add inline and script events
				result.listeners = result.listeners.concat(inlineEvents, scriptEvents);
				result.count = result.listeners.length;

				// Add note about browser limitations
				result.notes = [
					'Browser security restrictions prevent direct access to attached event listeners.',
					'This list shows visible event attributes and inferred listeners only.'
				];

				return JSON.stringify(result);
			})();
		" in tab_ref
	end tell

	return js_result
end listEventListeners

-- Add new event listeners to elements
on addEventListeners(tab_ref, selector, event_type, options_json)
	tell application "Safari"
		set js_code to "
			(function() {
				const options = " & options_json & ";
				const eventType = '" & event_type & "';
				let selector = '" & selector & "';

				if (!eventType) {
					return JSON.stringify({
						error: 'Event type is required'
					});
				}

				let elements = [];
				try {
					elements = Array.from(document.querySelectorAll(selector));
				} catch (error) {
					return JSON.stringify({
						error: 'Invalid selector: ' + error.message
					});
				}

				if (elements.length === 0) {
					return JSON.stringify({
						error: 'No elements found matching selector: ' + selector
					});
				}

				// Generate a unique function name for this event handler
				const handlerId = 'eventHandler_' + Math.random().toString(36).substr(2, 9);

				// Create a function to handle the event
				let handlerCode = options.handlerCode || 'console.log(\"Event: \" + event.type, event);';

				// Store the handler on the window so we can reference it later for removal
				window[handlerId] = new Function('event', handlerCode);

				// Track which elements we've attached to
				const attachedElements = [];

				// Add the event listener to each element
				elements.forEach((element, index) => {
					try {
						element.addEventListener(eventType, window[handlerId], {
							capture: !!options.capture,
							once: !!options.once,
							passive: !!options.passive
						});

						attachedElements.push({
							index: index,
							tagName: element.tagName,
							id: element.id || null,
							classes: element.className || null
						});
					} catch (error) {
						console.error('Error attaching event listener:', error);
					}
				});

				return JSON.stringify({
					success: true,
					handlerId: handlerId,
					eventType: eventType,
					elementsAffected: attachedElements.length,
					elements: attachedElements
				});
			})();
		"

		set js_result to do JavaScript js_code in tab_ref
	end tell

	return js_result
end addEventListeners

-- Remove event listeners from elements
on removeEventListeners(tab_ref, selector, event_type)
	tell application "Safari"
		set js_code to "
			(function() {
				const eventType = '" & event_type & "';
				let selector = '" & selector & "';

				if (!eventType) {
					return JSON.stringify({
						error: 'Event type is required'
					});
				}

				let elements = [];
				try {
					elements = Array.from(document.querySelectorAll(selector));
				} catch (error) {
					return JSON.stringify({
						error: 'Invalid selector: ' + error.message
					});
				}

				if (elements.length === 0) {
					return JSON.stringify({
						error: 'No elements found matching selector: ' + selector
					});
				}

				// We can't directly remove anonymous event listeners
				// Instead, we'll try to replace them with empty functions
				// This is a limitation of the browser security model

				const removedEvents = [];

				elements.forEach((element, index) => {
					// Handle inline event attributes
					const attrName = 'on' + eventType;
					if (element.hasAttribute(attrName)) {
						const originalHandler = element.getAttribute(attrName);
						element.removeAttribute(attrName);

						removedEvents.push({
							type: 'attribute',
							eventType: eventType,
							element: {
								index: index,
								tagName: element.tagName,
								id: element.id || null
							},
							original: originalHandler
						});
					}

					// Handle property-based event handlers
					const propName = 'on' + eventType;
					if (element[propName]) {
						const original = element[propName];
						element[propName] = null;

						removedEvents.push({
							type: 'property',
							eventType: eventType,
							element: {
								index: index,
								tagName: element.tagName,
								id: element.id || null
							},
							original: 'Function handler'
						});
					}

					// For addEventListener handlers, we can't access them
					// Add a note about this limitation
				});

				return JSON.stringify({
					success: true,
					elementsAffected: elements.length,
					removedEvents: removedEvents,
					notes: [
						'Browser security restrictions prevent removal of addEventListener handlers directly.',
						'Only inline event attributes and on-property handlers could be removed.'
					]
				});
			})();
		"

		set js_result to do JavaScript js_code in tab_ref
	end tell

	return js_result
end removeEventListeners

-- Monitor events as they occur
on monitorEvents(tab_ref, selector, event_types, duration)
	tell application "Safari"
		-- Set up the event monitoring
		set setup_js to "
			(function() {
				// Clean up any previous monitoring
				if (window._eventMonitor) {
					window._eventMonitor.cleanup();
				}

				// Determine which events to monitor
				let eventList = '" & event_types & "'.split(',').map(e => e.trim()).filter(e => e);
				if (eventList.length === 0) {
					// Monitor all common events if none specified
					eventList = [
						'click', 'dblclick', 'mousedown', 'mouseup', 'mousemove', 
						'keydown', 'keyup', 'keypress', 'focus', 'blur', 'change',
						'input', 'submit', 'reset', 'touchstart', 'touchend', 'touchmove'
					];
				}

				// Set up the observer
				const events = [];
				const elements = '" & selector & "' ? document.querySelectorAll('" & selector & "') : [document];

				// Create handler function for all events
				const handler = function(event) {
					// Record the event details
					if (events.length < 1000) { // Limit storage to prevent memory issues
						events.push({
							type: event.type,
							timeStamp: event.timeStamp,
							target: {
								tagName: event.target.tagName || 'DOCUMENT',
								id: event.target.id || null,
								className: event.target.className || null
							},
							currentTarget: {
								tagName: event.currentTarget.tagName || 'DOCUMENT',
								id: event.currentTarget.id || null,
								className: event.currentTarget.className || null
							},
							data: {
								clientX: event.clientX,
								clientY: event.clientY,
								key: event.key,
								code: event.code,
								value: event.target.value
							}
						});
					}
				};

				// Attach listeners
				const attachedListeners = [];

				Array.from(elements).forEach(element => {
					eventList.forEach(eventType => {
						element.addEventListener(eventType, handler);
						attachedListeners.push({
							element: element.tagName || 'document',
							event: eventType
						});
					});
				});

				// Create a cleanup function
				const cleanup = function() {
					Array.from(elements).forEach(element => {
						eventList.forEach(eventType => {
							element.removeEventListener(eventType, handler);
						});
					});
					delete window._eventMonitor;
					return {
						cleaned: true,
						eventCount: events.length
					};
				};

				// Store the monitor context globally so we can access it later
				window._eventMonitor = {
					events: events,
					cleanup: cleanup
				};

				return JSON.stringify({
					monitoring: true,
					events: eventList,
					elements: attachedListeners,
					duration: " & duration & "
				});
			})();
		"

		-- Set up the monitoring
		set setup_result to do JavaScript setup_js in tab_ref

		-- Wait for the specified duration
		delay duration

		-- Collect the results and clean up
		set collect_js to "
			(function() {
				if (!window._eventMonitor) {
					return JSON.stringify({
						error: 'Event monitor not found'
					});
				}

				const result = {
					events: window._eventMonitor.events,
					count: window._eventMonitor.events.length,
					summary: {}
				};

				// Generate event type summary
				window._eventMonitor.events.forEach(event => {
					if (!result.summary[event.type]) {
						result.summary[event.type] = 0;
					}
					result.summary[event.type]++;
				});

				// Clean up
				const cleanupResult = window._eventMonitor.cleanup();

				return JSON.stringify(result);
			})();
		"

		set collect_result to do JavaScript collect_js in tab_ref
	end tell

	return collect_result
end monitorEvents

-- Trigger events programmatically
on triggerEvent(tab_ref, selector, event_type, options_json)
	tell application "Safari"
		set js_code to "
			(function() {
				const options = " & options_json & ";
				const eventType = '" & event_type & "';
				let selector = '" & selector & "';

				if (!eventType) {
					return JSON.stringify({
						error: 'Event type is required'
					});
				}

				let elements = [];
				try {
					elements = Array.from(document.querySelectorAll(selector));
				} catch (error) {
					return JSON.stringify({
						error: 'Invalid selector: ' + error.message
					});
				}

				if (elements.length === 0) {
					return JSON.stringify({
						error: 'No elements found matching selector: ' + selector
					});
				}

				// Create the appropriate event object based on the event type
				let event;
				try {
					// Handle different event types
					switch (eventType) {
						case 'click':
						case 'dblclick':
						case 'mousedown':
						case 'mouseup':
						case 'mouseover':
						case 'mouseout':
						case 'mousemove':
							event = new MouseEvent(eventType, {
								bubbles: options.bubbles !== false,
								cancelable: options.cancelable !== false,
								view: window,
								detail: options.detail || 1,
								screenX: options.screenX || 0,
								screenY: options.screenY || 0,
								clientX: options.clientX || 0,
								clientY: options.clientY || 0,
								ctrlKey: options.ctrlKey || false,
								altKey: options.altKey || false,
								shiftKey: options.shiftKey || false,
								metaKey: options.metaKey || false,
								button: options.button || 0,
								relatedTarget: null
							});
							break;

						case 'keydown':
						case 'keyup':
						case 'keypress':
							event = new KeyboardEvent(eventType, {
								bubbles: options.bubbles !== false,
								cancelable: options.cancelable !== false,
								view: window,
								key: options.key || '',
								code: options.code || '',
								location: options.location || 0,
								ctrlKey: options.ctrlKey || false,
								altKey: options.altKey || false,
								shiftKey: options.shiftKey || false,
								metaKey: options.metaKey || false,
								repeat: options.repeat || false
							});
							break;

						case 'focus':
						case 'blur':
						case 'focusin':
						case 'focusout':
							event = new FocusEvent(eventType, {
								bubbles: options.bubbles !== false,
								cancelable: options.cancelable !== false,
								view: window,
								relatedTarget: options.relatedTarget || null
							});
							break;

						case 'input':
						case 'change':
						case 'submit':
						case 'reset':
							event = new Event(eventType, {
								bubbles: options.bubbles !== false,
								cancelable: options.cancelable !== false
							});
							break;

						default:
							// Generic event for other types
							event = new Event(eventType, {
								bubbles: options.bubbles !== false,
								cancelable: options.cancelable !== false
							});
					}
				} catch (error) {
					return JSON.stringify({
						error: 'Failed to create event: ' + error.message
					});
				}

				// Dispatch the event on each element
				const results = [];
				elements.forEach((element, index) => {
					try {
						// Set element value if provided (for input elements)
						if (options.value !== undefined && (element.tagName === 'INPUT' || 
														   element.tagName === 'TEXTAREA' || 
														   element.tagName === 'SELECT')) {
							element.value = options.value;
						}

						// Dispatch the event
						const dispatched = element.dispatchEvent(event);

						// Record the result
						results.push({
							index: index,
							element: {
								tagName: element.tagName,
								id: element.id || null,
								className: element.className || null
							},
							dispatched: dispatched,
							prevented: !dispatched
						});
					} catch (error) {
						results.push({
							index: index,
							element: {
								tagName: element.tagName,
								id: element.id || null,
								className: element.className || null
							},
							error: error.message
						});
					}
				});

				return JSON.stringify({
					success: true,
					eventType: eventType,
					elementsAffected: elements.length,
					results: results
				});
			})();
		"

		set js_result to do JavaScript js_code in tab_ref
	end tell

	return js_result
end triggerEvent

-- Analyze event propagation paths
on analyzeEventPropagation(tab_ref, selector, event_type)
	tell application "Safari"
		set js_code to "
			(function() {
				const eventType = '" & event_type & "' || 'click';
				let selector = '" & selector & "';

				if (!selector) {
					return JSON.stringify({
						error: 'Element selector is required'
					});
				}

				let element;
				try {
					element = document.querySelector(selector);
				} catch (error) {
					return JSON.stringify({
						error: 'Invalid selector: ' + error.message
					});
				}

				if (!element) {
					return JSON.stringify({
						error: 'No element found matching selector: ' + selector
					});
				}

				// Analyze the propagation path
				const propagationPath = [];
				let currentElement = element;

				while (currentElement) {
					// Check for event attributes
					const hasAttribute = currentElement.hasAttribute('on' + eventType);
					const hasProperty = !!currentElement['on' + eventType];

					propagationPath.push({
						tagName: currentElement.tagName || 'DOCUMENT',
						id: currentElement.id || null,
						className: currentElement.className || null,
						eventAttribute: hasAttribute,
						eventProperty: hasProperty,
						position: {
							top: currentElement.offsetTop,
							left: currentElement.offsetLeft,
							width: currentElement.offsetWidth,
							height: currentElement.offsetHeight
						}
					});

					currentElement = currentElement.parentElement;
				}

				// Add document as the final stop in the propagation
				propagationPath.push({
					tagName: 'DOCUMENT',
					id: null,
					className: null,
					eventAttribute: !!document['on' + eventType],
					eventProperty: !!document['on' + eventType],
					position: null
				});

				// Detect potential event stoppage points
				const stoppagePoints = document.querySelectorAll('[onclick*=\"stopPropagation\"], [onclick*=\"cancelBubble\"]');
				const stoppageNodes = Array.from(stoppagePoints).map(node => ({
					tagName: node.tagName,
					id: node.id || null,
					className: node.className || null,
					attribute: node.getAttribute('onclick')
				}));

				return JSON.stringify({
					eventType: eventType,
					targetElement: {
						tagName: element.tagName,
						id: element.id || null,
						className: element.className || null
					},
					propagationPath: propagationPath,
					pathLength: propagationPath.length,
					potentialStoppagePoints: stoppageNodes,
					notes: [
						'The propagation path shows the order of elements that would receive the event during bubbling.',
						'Browser security restrictions prevent detection of all event listeners that might stop propagation.',
						'Only inline attributes with stopPropagation() or cancelBubble can be detected as potential stoppage points.'
					]
				});
			})();
		"

		set js_result to do JavaScript js_code in tab_ref
	end tell

	return js_result
end analyzeEventPropagation

// Safari Form Filler
// Fills web forms with provided data in Safari

function run(argv) {
    // Default parameters when run without arguments
    if (argv.length === 0) {
        // Launch interactive mode with UI
        return runInteractiveMode();
    }

    return "Please use with MCP parameters";
}

// Main handler for MCP input parameters
function processMCPParameters(params) {
    try {
        // Extract parameters
        const url = params.url || "";                      // URL to open
        const formData = params.formData || {};            // Data to fill in form
        const selectors = params.selectors || {};          // Custom selectors
        const submit = params.submit === true;             // Whether to auto-submit
        const waitTime = params.waitTime || 5;             // Wait time in seconds after page load
        const fillDelay = params.fillDelay || 0.1;         // Delay between filling fields (seconds)

        // Validate required parameters
        if (!url) {
            return {
                success: false,
                error: "URL is required"
            };
        }

        if (Object.keys(formData).length === 0) {
            return {
                success: false,
                error: "Form data is required"
            };
        }

        // Fill the form
        return fillForm(url, formData, selectors, submit, waitTime, fillDelay);
    } catch (error) {
        return {
            success: false,
            error: `Error processing parameters: ${error.message}`
        };
    }
}

// Function to run interactive mode with dialog interfaces
function runInteractiveMode() {
    try {
        const app = Application.currentApplication();
        app.includeStandardAdditions = true;

        // Enter URL
        const url = app.displayDialog("Enter the website URL:", {
            defaultAnswer: "https://",
            withIcon: "note",
            buttons: ["Cancel", "Next"],
            defaultButton: "Next"
        }).textReturned;

        if (!url || !url.startsWith("http")) {
            return "Invalid URL. Please enter a URL starting with http:// or https://";
        }

        // Gather form data through dialogs
        let formData = {};
        let continueAdding = true;

        while (continueAdding) {
            const fieldName = app.displayDialog("Enter field name/label (or Cancel to finish):", {
                defaultAnswer: "",
                withIcon: "note",
                buttons: ["Finish", "Add Field"],
                defaultButton: "Add Field"
            });

            if (fieldName.buttonReturned === "Finish") {
                continueAdding = false;
                continue;
            }

            const fieldValue = app.displayDialog(`Enter value for "${fieldName.textReturned}":`, {
                defaultAnswer: "",
                withIcon: "note",
                buttons: ["Cancel", "Add"],
                defaultButton: "Add"
            });

            formData[fieldName.textReturned] = fieldValue.textReturned;
        }

        // Ask about submission
        const shouldSubmit = app.displayDialog("Would you like to automatically submit the form?", {
            withIcon: "note",
            buttons: ["No", "Yes"],
            defaultButton: "No"
        }).buttonReturned === "Yes";

        // Fill the form
        return fillForm(url, formData, {}, shouldSubmit, 5, 0.5);
    } catch (error) {
        if (error.errorNumber === -128) {
            return "Cancelled by user";
        }
        return `Error in interactive mode: ${error.message}`;
    }
}

// Main function to fill a form
function fillForm(url, formData, selectors, submit, waitTime, fillDelay) {
    try {
        const safari = Application("Safari");
        safari.includeStandardAdditions = true;

        // Activate Safari
        safari.activate();

        // Open URL
        const doc = safari.Document().make();
        doc.url = url;

        // Wait for page to load
        delay(waitTime);

        // Get the JavaScript to execute
        const jsScript = buildFormFillScript(formData, selectors, submit, fillDelay);

        // Execute the JavaScript in Safari
        const result = safari.doJavaScript(jsScript, {in: safari.documents[0]});

        return {
            success: true,
            message: "Form filled successfully",
            result: result
        };
    } catch (error) {
        return {
            success: false,
            error: `Error filling form: ${error.message}`
        };
    }
}

// Create the JavaScript to run in the browser context
function buildFormFillScript(formData, selectors, submit, fillDelay) {
    const customSelectors = JSON.stringify(selectors);
    const formDataJson = JSON.stringify(formData);
    const delayMs = fillDelay * 1000;

    return `
    (function() {
        // Form fill function
        const formData = ${formDataJson};
        const customSelectors = ${customSelectors};
        const shouldSubmit = ${submit};
        const fieldDelay = ${delayMs};

        // Helper function to delay execution
        const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

        // Helper function to find input elements
        async function findInputElement(fieldName) {
            // First, check if we have a custom selector for this field
            if (customSelectors[fieldName]) {
                return document.querySelector(customSelectors[fieldName]);
            }

            // Try various selector methods to find the input
            // 1. Try by ID
            let element = document.getElementById(fieldName);
            if (element) return element;

            // 2. Try by name attribute
            element = document.querySelector(\`[name="\${fieldName}"]\`);
            if (element) return element;

            // 3. Try by placeholder text
            element = document.querySelector(\`[placeholder*="\${fieldName}"]\`);
            if (element) return element;

            // 4. Try by aria-label
            element = document.querySelector(\`[aria-label*="\${fieldName}"]\`);
            if (element) return element;

            // 5. Try finding a label element containing the field name
            const labels = Array.from(document.querySelectorAll('label'));
            for (const label of labels) {
                if (label.textContent.toLowerCase().includes(fieldName.toLowerCase())) {
                    // If label has a 'for' attribute, use it to find the input
                    if (label.htmlFor) {
                        element = document.getElementById(label.htmlFor);
                        if (element) return element;
                    }

                    // Check for inputs inside the label
                    const inputInLabel = label.querySelector('input, select, textarea');
                    if (inputInLabel) return inputInLabel;

                    // Check for inputs after the label
                    let sibling = label.nextElementSibling;
                    while (sibling) {
                        if (sibling.matches('input, select, textarea')) {
                            return sibling;
                        }
                        // Check for input inside the sibling
                        const nestedInput = sibling.querySelector('input, select, textarea');
                        if (nestedInput) return nestedInput;

                        sibling = sibling.nextElementSibling;
                    }
                }
            }

            // 6. Try by class or name containing the field name
            element = document.querySelector(\`[class*="\${fieldName}"]\`) || 
                      document.querySelector(\`[name*="\${fieldName}"]\`);
            if (element) return element;

            // 7. Try by input type for common fields
            const commonFields = {
                'email': 'input[type="email"]',
                'password': 'input[type="password"]',
                'username': 'input[type="text"], input:not([type])',
                'search': 'input[type="search"]',
                'phone': 'input[type="tel"]',
                'date': 'input[type="date"]'
            };

            if (commonFields[fieldName.toLowerCase()]) {
                element = document.querySelector(commonFields[fieldName.toLowerCase()]);
                if (element) return element;
            }

            return null;
        }

        // Function to set value based on element type
        async function setValue(element, value) {
            if (!element) return false;

            const tagName = element.tagName.toLowerCase();
            const inputType = element.type ? element.type.toLowerCase() : '';

            // Handle different input types
            if (tagName === 'select') {
                // For select elements, find the option that matches the value
                const options = Array.from(element.options);
                for (const option of options) {
                    if (option.text.includes(value) || option.value.includes(value)) {
                        element.value = option.value;
                        element.dispatchEvent(new Event('change', { bubbles: true }));
                        return true;
                    }
                }
                return false;
            } 
            else if (inputType === 'checkbox' || inputType === 'radio') {
                // For checkboxes and radios
                const lowercaseValue = value.toString().toLowerCase();
                const shouldCheck = ['true', 'yes', 'on', '1'].includes(lowercaseValue);
                element.checked = shouldCheck;
                element.dispatchEvent(new Event('change', { bubbles: true }));
                return true;
            }
            else if (tagName === 'textarea' || tagName === 'input') {
                // Clear the current value first
                element.value = '';
                element.dispatchEvent(new Event('input', { bubbles: true }));
                await sleep(50); // Small delay after clearing

                // Set the new value
                element.value = value;

                // Dispatch events to trigger any listeners
                element.dispatchEvent(new Event('input', { bubbles: true }));
                element.dispatchEvent(new Event('change', { bubbles: true }));
                return true;
            }
            else {
                // For other elements, try setting innerText or textContent
                if (typeof element.value !== 'undefined') {
                    element.value = value;
                } else {
                    element.textContent = value;
                }
                return true;
            }
        }

        // Main function to fill the form
        async function fillForm() {
            let results = {};
            let errors = [];

            for (const fieldName of Object.keys(formData)) {
                try {
                    // Find the element
                    const element = await findInputElement(fieldName);

                    if (!element) {
                        errors.push(\`Could not find element for: \${fieldName}\`);
                        continue;
                    }

                    // Set the value
                    const success = await setValue(element, formData[fieldName]);

                    if (success) {
                        results[fieldName] = 'filled';
                    } else {
                        errors.push(\`Could not set value for: \${fieldName}\`);
                    }

                    // Add delay between fields
                    if (fieldDelay > 0) {
                        await sleep(fieldDelay);
                    }
                } catch (error) {
                    errors.push(\`Error processing \${fieldName}: \${error.message}\`);
                }
            }

            // Submit the form if requested
            if (shouldSubmit) {
                try {
                    // Try to find the submit button
                    let submitButton = document.querySelector('button[type="submit"]') || 
                                      document.querySelector('input[type="submit"]');

                    // If no submit button found, look for buttons with submit-related text
                    if (!submitButton) {
                        const buttons = Array.from(document.querySelectorAll('button, input[type="button"], a.button, .btn, [role="button"]'));
                        for (const button of buttons) {
                            const text = button.textContent.toLowerCase();
                            if (text.includes('submit') || text.includes('login') || 
                                text.includes('sign in') || text.includes('continue') ||
                                text.includes('register') || text.includes('next')) {
                                submitButton = button;
                                break;
                            }
                        }
                    }

                    // If we found a submit button, click it
                    if (submitButton) {
                        submitButton.click();
                        results['formSubmitted'] = true;
                    } else {
                        // If no button found, try to submit the form directly
                        const form = document.querySelector('form');
                        if (form) {
                            form.submit();
                            results['formSubmitted'] = true;
                        } else {
                            errors.push('Could not find a submit button or form element');
                        }
                    }
                } catch (error) {
                    errors.push(\`Error submitting form: \${error.message}\`);
                }
            }

            return {
                success: errors.length === 0,
                filled: results,
                errors: errors
            };
        }

        // Execute the form filling and return the result
        return fillForm();
    })();
    `;
}

// Utility function to create a delay
function delay(seconds) {
    const app = Application.currentApplication();
    app.includeStandardAdditions = true;
    app.delay(seconds);
}

--MCP_INPUT:formData
--MCP_INPUT:formSelector
--MCP_INPUT:submit

on manipulateForms(formDataJson, formSelector, shouldSubmit)
  -- Validate inputs
  if formDataJson is missing value or formDataJson is "" then
    return "error: Form data not provided."
  end if

  -- Set default values
  if formSelector is missing value or formSelector is "" then
    set formSelector to "form"
  end if

  set doSubmit to false
  if shouldSubmit is not missing value and shouldSubmit is not "" then
    if shouldSubmit is "true" or shouldSubmit is "yes" or shouldSubmit is "1" then
      set doSubmit to true
    end if
  end if

  -- Construct JavaScript for form manipulation
  set formJS to "
    (function() {
      // Parse form data
      let formData;
      try {
        formData = " & formDataJson & ";
      } catch (error) {
        return JSON.stringify({
          error: `Invalid JSON in form data: ${error.message}`
        });
      }

      // Target form
      const formSelector = '" & formSelector & "';
      const forms = document.querySelectorAll(formSelector);

      if (forms.length === 0) {
        return JSON.stringify({
          error: `No forms found matching selector: ${formSelector}`
        });
      }

      // We'll track all actions for the results report
      const results = {
        successful: [],
        failed: [],
        form: formSelector,
        formCount: forms.length
      };

      // Process each matching form
      forms.forEach((form, formIndex) => {
        // Process each field in the form data
        Object.entries(formData).forEach(([fieldKey, fieldValue]) => {
          try {
            // Field can be identified by name, id, or selector
            let field = null;

            // Try finding by name
            field = form.elements[fieldKey];

            // If not found, try as ID
            if (!field) {
              field = form.querySelector(`#${fieldKey}`);
            }

            // If still not found, use as a CSS selector
            if (!field) {
              field = form.querySelector(fieldKey);
            }

            // Skip if field not found
            if (!field) {
              results.failed.push({
                field: fieldKey,
                reason: 'Field not found in form'
              });
              return;
            }

            // Handle different input types
            switch (field.type) {
              case 'checkbox':
                // Convert various true/false representations
                let isChecked = false;
                if (fieldValue === true || fieldValue === 1 || fieldValue === '1' || 
                    fieldValue === 'true' || fieldValue === 'yes' || fieldValue === 'on') {
                  isChecked = true;
                }
                field.checked = isChecked;

                // Dispatch change event
                field.dispatchEvent(new Event('change', { bubbles: true }));
                results.successful.push({
                  field: fieldKey,
                  type: 'checkbox',
                  value: isChecked
                });
                break;

              case 'radio':
                // For radio buttons, we need to find the one with matching value
                const radioGroup = form.querySelectorAll(`input[type='radio'][name='${field.name}']`);
                let radioFound = false;

                radioGroup.forEach(radio => {
                  if (radio.value == fieldValue) {
                    radio.checked = true;
                    radio.dispatchEvent(new Event('change', { bubbles: true }));
                    radioFound = true;
                  }
                });

                if (radioFound) {
                  results.successful.push({
                    field: fieldKey,
                    type: 'radio',
                    value: fieldValue
                  });
                } else {
                  results.failed.push({
                    field: fieldKey,
                    reason: `Radio option with value '${fieldValue}' not found`
                  });
                }
                break;

              case 'select-one':
                // Single select dropdown
                let selectFound = false;

                // Try to find option by value
                for (let i = 0; i < field.options.length; i++) {
                  if (field.options[i].value == fieldValue) {
                    field.selectedIndex = i;
                    selectFound = true;
                    break;
                  }
                }

                // If not found by value, try to find by text
                if (!selectFound) {
                  for (let i = 0; i < field.options.length; i++) {
                    if (field.options[i].text == fieldValue) {
                      field.selectedIndex = i;
                      selectFound = true;
                      break;
                    }
                  }
                }

                if (selectFound) {
                  field.dispatchEvent(new Event('change', { bubbles: true }));
                  results.successful.push({
                    field: fieldKey,
                    type: 'select',
                    value: fieldValue
                  });
                } else {
                  results.failed.push({
                    field: fieldKey,
                    reason: `Option with value or text '${fieldValue}' not found in select`
                  });
                }
                break;

              case 'select-multiple':
                // Multi-select dropdown - value should be an array
                if (!Array.isArray(fieldValue)) {
                  results.failed.push({
                    field: fieldKey,
                    reason: 'Value for multi-select must be an array'
                  });
                  break;
                }

                // First deselect all options
                for (let i = 0; i < field.options.length; i++) {
                  field.options[i].selected = false;
                }

                // Now select the specified options
                let multiSelectFound = false;
                fieldValue.forEach(value => {
                  let optionFound = false;

                  // Try to find by value
                  for (let i = 0; i < field.options.length; i++) {
                    if (field.options[i].value == value) {
                      field.options[i].selected = true;
                      optionFound = true;
                      multiSelectFound = true;
                      break;
                    }
                  }

                  // If not found by value, try by text
                  if (!optionFound) {
                    for (let i = 0; i < field.options.length; i++) {
                      if (field.options[i].text == value) {
                        field.options[i].selected = true;
                        optionFound = true;
                        multiSelectFound = true;
                        break;
                      }
                    }
                  }
                });

                if (multiSelectFound) {
                  field.dispatchEvent(new Event('change', { bubbles: true }));
                  results.successful.push({
                    field: fieldKey,
                    type: 'select-multiple',
                    value: fieldValue
                  });
                } else {
                  results.failed.push({
                    field: fieldKey,
                    reason: 'None of the specified options were found in the multi-select'
                  });
                }
                break;

              case 'file':
                // File input - we'll use a data URL or local file path
                try {
                  // This is tricky because of security restrictions
                  // We'll try using a programmatic approach
                  const dataTransfer = new DataTransfer();

                  // Create a mock file
                  let fileData;
                  let fileName;

                  if (typeof fieldValue === 'string') {
                    if (fieldValue.startsWith('data:')) {
                      // It's a data URL
                      const [header, content] = fieldValue.split(',');
                      const mimeType = header.match(/data:(.*?);/)[1];
                      const extension = mimeType.split('/')[1];
                      fileName = `file-${Date.now()}.${extension}`;

                      // Convert base64 to blob
                      const binaryString = window.atob(content);
                      const len = binaryString.length;
                      const bytes = new Uint8Array(len);
                      for (let i = 0; i < len; i++) {
                        bytes[i] = binaryString.charCodeAt(i);
                      }
                      fileData = new Blob([bytes], { type: mimeType });
                    } else {
                      // Assume it's a file path - this actually won't work directly due to security
                      // But we can create a mock file
                      fileName = fieldValue.split('/').pop();
                      fileData = new Blob(['Mock file content'], { type: 'text/plain' });
                    }
                  } else if (typeof fieldValue === 'object' && fieldValue.name && fieldValue.content) {
                    // Object with name and content
                    fileName = fieldValue.name;
                    if (typeof fieldValue.content === 'string' && fieldValue.content.startsWith('data:')) {
                      // Data URL in content
                      const [header, content] = fieldValue.content.split(',');
                      const mimeType = header.match(/data:(.*?);/)[1];

                      // Convert base64 to blob
                      const binaryString = window.atob(content);
                      const len = binaryString.length;
                      const bytes = new Uint8Array(len);
                      for (let i = 0; i < len; i++) {
                        bytes[i] = binaryString.charCodeAt(i);
                      }
                      fileData = new Blob([bytes], { type: mimeType });
                    } else {
                      // Plain text content
                      fileData = new Blob([fieldValue.content || ''], { type: 'text/plain' });
                    }
                  } else {
                    throw new Error('Invalid file data format');
                  }

                  // Create a File object
                  const file = new File([fileData], fileName, { 
                    type: fileData.type,
                    lastModified: Date.now()
                  });

                  // Add to DataTransfer
                  dataTransfer.items.add(file);

                  // Set files property
                  field.files = dataTransfer.files;
                  field.dispatchEvent(new Event('change', { bubbles: true }));

                  results.successful.push({
                    field: fieldKey,
                    type: 'file',
                    value: fileName
                  });
                } catch (fileError) {
                  results.failed.push({
                    field: fieldKey,
                    reason: `File input error: ${fileError.message}`
                  });
                }
                break;

              case 'date':
              case 'datetime-local':
              case 'month':
              case 'time':
              case 'week':
                // Date and time inputs
                field.value = fieldValue;
                field.dispatchEvent(new Event('input', { bubbles: true }));
                field.dispatchEvent(new Event('change', { bubbles: true }));
                results.successful.push({
                  field: fieldKey,
                  type: field.type,
                  value: fieldValue
                });
                break;

              case 'range':
                // Range slider
                field.value = fieldValue;
                field.dispatchEvent(new Event('input', { bubbles: true }));
                field.dispatchEvent(new Event('change', { bubbles: true }));
                results.successful.push({
                  field: fieldKey,
                  type: 'range',
                  value: fieldValue
                });
                break;

              case 'color':
                // Color picker - value should be a hex color
                field.value = fieldValue;
                field.dispatchEvent(new Event('input', { bubbles: true }));
                field.dispatchEvent(new Event('change', { bubbles: true }));
                results.successful.push({
                  field: fieldKey,
                  type: 'color',
                  value: fieldValue
                });
                break;

              default:
                // Text, email, password, number, url, search, tel, textarea, etc.
                field.value = fieldValue;

                // Trigger events to simulate user input
                field.dispatchEvent(new Event('focus', { bubbles: true }));
                field.dispatchEvent(new Event('input', { bubbles: true }));
                field.dispatchEvent(new Event('change', { bubbles: true }));
                field.dispatchEvent(new Event('blur', { bubbles: true }));

                results.successful.push({
                  field: fieldKey,
                  type: field.type || 'text',
                  value: fieldValue
                });
                break;
            }
          } catch (error) {
            results.failed.push({
              field: fieldKey,
              reason: `Error: ${error.message}`
            });
          }
        });
      });

      // Submit the form if requested
      const shouldSubmit = " & (doSubmit as string) & ";
      if (shouldSubmit) {
        try {
          const form = forms[0]; // Submit the first matching form

          // Add a flag to detect when page starts loading
          window._formSubmissionInProgress = true;

          // Submit the form
          form.submit();

          // Note: We won't be able to return after navigation,
          // so the 'submitted' status may not be included in the result
          results.submitted = true;
        } catch (submitError) {
          results.submitError = submitError.message;
        }
      }

      return JSON.stringify(results, null, 2);
    })();
  "

  tell application "Safari"
    if not running then
      return "error: Safari is not running."
    end if

    try
      if (count of windows) is 0 or (count of tabs of front window) is 0 then
        return "error: No tabs open in Safari."
      end if

      set currentTab to current tab of front window

      -- Execute the JavaScript
      set jsResult to do JavaScript formJS in currentTab

      return jsResult
    on error errMsg
      return "error: Failed to manipulate form - " & errMsg & ". Make sure 'Allow JavaScript from Apple Events' is enabled in Safari's Develop menu."
    end try
  end tell
end manipulateForms

return my manipulateForms("--MCP_INPUT:formData", "--MCP_INPUT:formSelector", "--MCP_INPUT:submit")

--MCP_INPUT:selector
--MCP_INPUT:attributes
--MCP_INPUT:mode

on getDOMInfo(selector, attributesToGet, extractionMode)
  -- Validate inputs
  if selector is missing value or selector is "" then
    return "error: CSS selector not provided."
  end if

  -- Set default mode if not specified
  if extractionMode is missing value or extractionMode is "" then
    set extractionMode to "json"
  else
    set extractionMode to my toLowerCase(extractionMode)
    if extractionMode is not "text" and extractionMode is not "html" and extractionMode is not "json" then
      return "error: Invalid extraction mode. Must be 'text', 'html', or 'json'."
    end if
  end if

  -- Prepare the list of attributes to extract
  set attributeList to "[]"
  if attributesToGet is not missing value and attributesToGet is not "" then
    -- Convert comma-separated list to JavaScript array
    set attributeList to "[" & my convertToJSStringArray(attributesToGet) & "]"
  end if

  -- Build the JavaScript to extract DOM info
  set domExtractionJS to "
    (function() {
      // CSS selector to use
      const selector = '" & selector & "';

      // Attributes to extract (if specified)
      const attributesToGet = " & attributeList & ";

      // Function to get computed styles in simplified object form
      function getComputedStylesForElement(element) {
        const computedStyle = window.getComputedStyle(element);
        const styles = {};

        // Filter for the most useful style properties
        const keyProperties = [
          'display', 'visibility', 'position', 'width', 'height', 
          'top', 'right', 'bottom', 'left', 'margin', 'padding',
          'color', 'background-color', 'font-size', 'font-family',
          'z-index', 'opacity', 'border', 'overflow'
        ];

        keyProperties.forEach(prop => {
          // For shorthand properties like 'margin', try individual sides as well
          if (prop === 'margin' || prop === 'padding' || prop === 'border') {
            ['top', 'right', 'bottom', 'left'].forEach(side => {
              styles[`${prop}-${side}`] = computedStyle.getPropertyValue(`${prop}-${side}`);
            });
          } else {
            styles[prop] = computedStyle.getPropertyValue(prop);
          }
        });

        return styles;
      }

      // Function to get element metrics/dimensions
      function getElementMetrics(element) {
        const rect = element.getBoundingClientRect();
        return {
          x: rect.x,
          y: rect.y,
          width: rect.width,
          height: rect.height,
          top: rect.top,
          right: rect.right,
          bottom: rect.bottom,
          left: rect.left,
          inViewport: (
            rect.top >= 0 &&
            rect.left >= 0 &&
            rect.bottom <= window.innerHeight &&
            rect.right <= window.innerWidth
          )
        };
      }

      // Function to get all attributes of an element
      function getElementAttributes(element, specificAttributes = []) {
        const attributes = {};
        const attrs = element.attributes;

        if (attrs && attrs.length > 0) {
          // If specific attributes requested, only get those
          if (specificAttributes.length > 0) {
            specificAttributes.forEach(attrName => {
              if (element.hasAttribute(attrName)) {
                attributes[attrName] = element.getAttribute(attrName);
              }
            });
          } else {
            // Otherwise get all attributes
            for (let i = 0; i < attrs.length; i++) {
              attributes[attrs[i].name] = attrs[i].value;
            }
          }
        }

        return attributes;
      }

      // Function to extract comprehensive info about an element
      function extractElementInfo(element, mode, specificAttributes) {
        // For text mode, just return the text content
        if (mode === 'text') {
          return element.textContent.trim();
        }

        // For HTML mode, return the outer HTML
        if (mode === 'html') {
          return element.outerHTML;
        }

        // For JSON mode, return detailed information
        return {
          tagName: element.tagName.toLowerCase(),
          id: element.id || null,
          className: element.className || null,
          textContent: element.textContent.trim(),
          attributes: getElementAttributes(element, specificAttributes),
          styles: getComputedStylesForElement(element),
          metrics: getElementMetrics(element),
          // Include simplified HTML for reference
          html: element.outerHTML.length > 500 
            ? element.outerHTML.substring(0, 500) + '...' 
            : element.outerHTML
        };
      }

      // Find elements matching the selector
      let elements = [];
      try {
        elements = Array.from(document.querySelectorAll(selector));

        // If no elements found in main document, try looking in frames
        if (elements.length === 0 && window.frames.length > 0) {
          for (let i = 0; i < window.frames.length; i++) {
            try {
              const frameElements = Array.from(window.frames[i].document.querySelectorAll(selector));
              if (frameElements.length > 0) {
                elements = frameElements;
                break;
              }
            } catch (frameError) {
              // Ignore errors accessing frames (could be cross-origin)
            }
          }
        }
      } catch (err) {
        return JSON.stringify({
          error: `Invalid selector: ${err.message}`
        });
      }

      // Check if we found any elements
      if (elements.length === 0) {
        return JSON.stringify({
          error: `No elements found matching selector: ${selector}`
        });
      }

      // Extract information based on mode
      const extractionMode = '" & extractionMode & "';
      const results = elements.map(el => extractElementInfo(el, extractionMode, attributesToGet));

      // Format the response based on extraction mode and number of elements
      if (extractionMode === 'text' || extractionMode === 'html') {
        // For text/html modes with single element, return the content directly
        if (elements.length === 1) {
          return results[0];
        }
        // Otherwise return as JSON array
        return JSON.stringify(results);
      } else {
        // For JSON mode, always return a structured object
        return JSON.stringify({
          selector: selector,
          count: elements.length,
          elements: results
        }, null, 2);
      }
    })();
  "

  tell application "Safari"
    if not running then
      return "error: Safari is not running."
    end if

    try
      if (count of windows) is 0 or (count of tabs of front window) is 0 then
        return "error: No tabs open in Safari."
      end if

      set currentTab to current tab of front window
      set pageUrl to URL of currentTab

      -- Execute the JavaScript
      set jsResult to do JavaScript domExtractionJS in currentTab

      return jsResult
    on error errMsg
      return "error: Failed to extract DOM information - " & errMsg & ". Make sure 'Allow JavaScript from Apple Events' is enabled in Safari's Develop menu."
    end try
  end tell
end getDOMInfo

-- Helper function to convert comma-separated list to JavaScript string array
on convertToJSStringArray(commaList)
  set AppleScript's text item delimiters to ","
  set theItems to every text item of commaList
  set AppleScript's text item delimiters to ""

  set jsArray to ""
  repeat with i from 1 to count of theItems
    set theItem to item i of theItems
    set theItem to my trimText(theItem)
    if theItem is not "" then
      set jsArray to jsArray & "\"" & theItem & "\""
      if i < count of theItems then set jsArray to jsArray & ", "
    end if
  end repeat

  return jsArray
end convertToJSStringArray

-- Helper function to trim whitespace
on trimText(theText)
  -- Remove leading and trailing whitespace
  set theText to my trimLeadingSpace(theText)
  set theText to my trimTrailingSpace(theText)
  return theText
end trimText

-- Helper function to remove leading whitespace
on trimLeadingSpace(theText)
  repeat while theText begins with " " or theText begins with tab
    set theText to text 2 thru end of theText
  end repeat
  return theText
end trimLeadingSpace

-- Helper function to remove trailing whitespace
on trimTrailingSpace(theText)
  repeat while theText ends with " " or theText ends with tab
    set theText to text 1 thru ((length of theText) - 1) of theText
  end repeat
  return theText
end trimTrailingSpace

-- Helper function to convert text to lowercase
on toLowerCase(sourceText)
  set lowercaseText to ""
  set upperChars to "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
  set lowerChars to "abcdefghijklmnopqrstuvwxyz"

  repeat with i from 1 to length of sourceText
    set currentChar to character i of sourceText
    set charPos to offset of currentChar in upperChars

    if charPos > 0 then
      set lowercaseText to lowercaseText & character charPos of lowerChars
    else
      set lowercaseText to lowercaseText & currentChar
    end if
  end repeat

  return lowercaseText
end toLowerCase

return my getDOMInfo("--MCP_INPUT:selector", "--MCP_INPUT:attributes", "--MCP_INPUT:mode")

--MCP_INPUT:script
--MCP_INPUT:scriptUrl
--MCP_INPUT:persistent

on injectJavaScript(scriptCode, scriptUrl, persistent)
  -- Validate inputs
  if (scriptCode is missing value or scriptCode is "") and (scriptUrl is missing value or scriptUrl is "") then
    return "error: Either script code or script URL must be provided."
  end if

  -- Set default for persistent flag
  set shouldPersist to false
  if persistent is not missing value and persistent is not "" then
    if persistent is "true" or persistent is "yes" or persistent is "1" then
      set shouldPersist to true
    end if
  end if

  -- Prepare the JavaScript to be injected
  set injectionJS to ""

  -- Handle loading external script if URL is provided
  if scriptUrl is not missing value and scriptUrl is not "" then
    set injectionJS to "
      (function() {
        // Function to load external script
        function loadScript(url) {
          return new Promise((resolve, reject) => {
            const script = document.createElement('script');
            script.src = url;
            script.onload = resolve;
            script.onerror = () => reject(new Error(`Failed to load script: ${url}`));
            document.head.appendChild(script);
          });
        }

        // Load the external script
        try {
          loadScript('" & scriptUrl & "')
            .then(() => {
              console.log('External script loaded successfully: " & scriptUrl & "');
            })
            .catch(error => {
              console.error(error);
            });
        } catch(e) {
          console.error('Error loading external script:', e);
          throw e;
        }
      })();
    "
  end if

  -- If direct script code is provided, add it to the injection
  if scriptCode is not missing value and scriptCode is not "" then
    -- Prepare the direct script code
    set injectionJS to injectionJS & "
      (function() {
        try {
          " & scriptCode & "
        } catch(e) {
          console.error('Error executing injected script:', e);
          throw e;
        }
      })();
    "
  end if

  -- Add persistence code if requested
  if shouldPersist then
    set persistCode to "
      // Add persistence observer
      (function setupPersistence() {
        // Create a unique ID for our injected script to avoid duplicates
        const scriptId = 'safari-injected-script-' + Math.random().toString(36).substring(2);

        // Create a flag on window to track if we've already set up persistence
        if (window._safariScriptInjectionObserver) {
          console.log('Persistence observer already exists');
          return;
        }

        // Function to re-inject our code when DOM changes
        const reInjectOnChange = function() {
          // Store our code in sessionStorage for re-injection
          sessionStorage.setItem(scriptId, `" & my escapeForJS(injectionJS) & "`);

          // Set up a MutationObserver to watch for DOM changes
          const observer = new MutationObserver((mutations) => {
            // Throttle execution to avoid excessive re-runs
            if (!window._safariScriptInjectionThrottled) {
              window._safariScriptInjectionThrottled = true;
              setTimeout(() => {
                try {
                  // Re-execute our stored code
                  eval(sessionStorage.getItem(scriptId));
                  console.log('Re-injected script after DOM change');
                } catch(e) {
                  console.error('Error re-injecting script:', e);
                }
                window._safariScriptInjectionThrottled = false;
              }, 1000);
            }
          });

          // Start observing
          observer.observe(document.body, {
            childList: true,
            subtree: true
          });

          // Store the observer for reference
          window._safariScriptInjectionObserver = observer;
          console.log('Persistence observer set up for injected script');
        };

        // Call immediately and also set up to run when page is fully loaded
        reInjectOnChange();
        if (document.readyState === 'complete') {
          reInjectOnChange();
        } else {
          window.addEventListener('load', reInjectOnChange);
        }
      })();
    "

    -- Add the persistence code to our injection
    set injectionJS to injectionJS & persistCode
  end if

  -- Execute the prepared JavaScript in Safari
  tell application "Safari"
    if not running then
      return "error: Safari is not running."
    end if

    try
      if (count of windows) is 0 or (count of tabs of front window) is 0 then
        return "error: No tabs open in Safari."
      end if

      set currentTab to current tab of front window
      set pageUrl to URL of currentTab

      -- Execute the JavaScript
      set jsResult to do JavaScript injectionJS in currentTab

      -- Handle the result
      if jsResult is missing value then
        if scriptUrl is not missing value and scriptUrl is not "" then
          set successMsg to "Successfully injected external script from: " & scriptUrl
        else
          set successMsg to "Successfully injected JavaScript code"
        end if

        if shouldPersist then
          return successMsg & " with persistence enabled."
        else
          return successMsg & "."
        end if
      else
        return jsResult
      end if
    on error errMsg
      return "error: Failed to inject JavaScript - " & errMsg & ". Make sure 'Allow JavaScript from Apple Events' is enabled in Safari's Develop menu."
    end try
  end tell
end injectJavaScript

-- Helper function to escape JavaScript for embedding in another JavaScript string
on escapeForJS(jsCode)
  -- Replace backslashes first
  set escapedCode to my replaceText(jsCode, "\\", "\\\\")
  -- Replace newlines
  set escapedCode to my replaceText(escapedCode, return, "\\n")
  -- Replace quotes
  set escapedCode to my replaceText(escapedCode, "\"", "\\\"")
  -- Replace backticks
  set escapedCode to my replaceText(escapedCode, "`", "\\`")

  return escapedCode
end escapeForJS

-- Helper function to replace text
on replaceText(theText, searchString, replacementString)
