  -- Replace newlines
  set escapedString to my replaceText(escapedString, return, "\\n")
  -- Replace quotes
  set escapedString to my replaceText(escapedString, "\"", "\\\"")
  -- Replace backticks
  set escapedString to my replaceText(escapedString, "`", "\\`")

  return escapedString
end escapeJSString

