on analyzePerformance(analysisType, testURL)
  -- Validate analysis type
  if analysisType is missing value or analysisType is "" then
    set analysisType to "all"
  else
    set analysisType to my toLowerCase(analysisType)
    if analysisType is not "page" and analysisType is not "javascript" and analysisType is not "memory" and analysisType is not "resources" and analysisType is not "all" then
      return "error: Invalid analysis type. Must be 'page', 'javascript', 'memory', 'resources', or 'all'."
    end if
  end if

  -- Check if we need to open a URL first
  set needToOpenURL to false
  if testURL is not missing value and testURL is not "" then
    set needToOpenURL to true

    -- Ensure URL has protocol
    if testURL does not start with "http://" and testURL does not start with "https://" then
      set testURL to "https://" & testURL
    end if
  end if

  -- Prepare performance analysis JavaScript
  set perfJS to "
    (function() {
      // Start timer for our own script's execution time
      const scriptStartTime = performance.now();

      // Analyze navigation and page load performance
      function analyzePagePerformance() {
        const result = {
          metrics: {
            timing: {},
            navigation: {}
          },
          domInfo: {}
        };

        // Check if Navigation Timing API is available
        if (window.performance && performance.timing) {
          const timing = performance.timing;

          // Calculate key metrics
          result.metrics.timing = {
            // DNS lookup time
            dnsLookup: timing.domainLookupEnd - timing.domainLookupStart,

            // Connection time
            tcpConnection: timing.connectEnd - timing.connectStart,

            // Server response time
            serverResponse: timing.responseEnd - timing.requestStart,

            // Document download time
            documentDownload: timing.responseEnd - timing.responseStart,

            // DOM processing time
            domProcessing: timing.domComplete - timing.domLoading,

            // DOM content loaded
            domContentLoaded: timing.domContentLoadedEventEnd - timing.navigationStart,

            // Window load event
            windowLoad: timing.loadEventEnd - timing.navigationStart,

            // Total page load time
            totalPageLoad: timing.loadEventEnd - timing.navigationStart,

            // Time to first byte
            timeToFirstByte: timing.responseStart - timing.navigationStart,

            // Time to interactive
            timeToInteractive: timing.domInteractive - timing.navigationStart
          };

          // Navigation type
          if (performance.navigation) {
            const navType = performance.navigation.type;
            if (navType === 0) {
              result.metrics.navigation.type = 'Navigation: Direct entry or link';
            } else if (navType === 1) {
              result.metrics.navigation.type = 'Navigation: Reload';
            } else if (navType === 2) {
              result.metrics.navigation.type = 'Navigation: Back/forward button';
            } else {
              result.metrics.navigation.type = 'Navigation: Other/unknown';
            }

            result.metrics.navigation.redirectCount = performance.navigation.redirectCount;
          }
        } else {
          result.metrics.error = 'Navigation Timing API not available';
        }

        // DOM statistics
        result.domInfo = {
          elementCount: document.getElementsByTagName('*').length,
          scriptCount: document.getElementsByTagName('script').length,
          styleSheetCount: document.styleSheets.length,
          domDepth: getDOMDepth(document.body),
          eventListenerCount: estimateEventListeners()
        };

        return result;
      }

      // Analyze JavaScript performance
      function analyzeJavaScriptPerformance() {
        const result = {
          scriptExecution: {},
          jsErrors: []
        };

        // Measure DOM event handlers' execution time (approximate)
        result.scriptExecution.eventHandlers = measureEventHandlers();

        // Snapshot of recent JavaScript errors
        try {
          // Try to access previous errors if any
          if (window._jsErrorLog) {
            result.jsErrors = window._jsErrorLog;
          }

          // Set up error logging for future errors
          if (!window._jsErrorLogSetup) {
            window._jsErrorLog = [];
            window.addEventListener('error', function(error) {
              window._jsErrorLog.push({
                message: error.message,
                source: error.filename,
                lineNumber: error.lineno,
                columnNumber: error.colno,
                timestamp: new Date().toISOString()
              });
            });
            window._jsErrorLogSetup = true;
          }
        } catch (e) {
          result.jsErrors.push({
            message: 'Error setting up JS error logging: ' + e.message
          });
        }

        return result;
      }

      // Analyze memory usage
      function analyzeMemoryUsage() {
        const result = {
          general: {},
          detailed: {}
        };

        // Basic memory info (might not be available in all browsers)
        if (window.performance && performance.memory) {
          result.general = {
            jsHeapSizeLimit: formatBytes(performance.memory.jsHeapSizeLimit),
            totalJSHeapSize: formatBytes(performance.memory.totalJSHeapSize),
            usedJSHeapSize: formatBytes(performance.memory.usedJSHeapSize),
            heapUtilization: (performance.memory.usedJSHeapSize / performance.memory.totalJSHeapSize * 100).toFixed(2) + '%'
          };
        } else {
          result.general.status = 'Memory performance API not available';
        }

        // DOM memory usage estimation
        const domSnapshot = {
          elementCount: document.getElementsByTagName('*').length,
          nodeCount: document.getElementsByTagName('*').length + document.createTreeWalker(document, NodeFilter.SHOW_COMMENT).filter(() => true).length,
          textNodeCount: document.createTreeWalker(document, NodeFilter.SHOW_TEXT).filter(() => true).length,
          attributeCount: countAttributes(),
          estimatedMemoryUsage: 'Unknown'
        };

        // Rough estimation of DOM memory usage (very approximate)
        // Typical element ~1-2KB, text node ~50-100 bytes, attribute ~40 bytes
        const estimatedBytes = 
          domSnapshot.elementCount * 1500 +
          domSnapshot.textNodeCount * 80 +
          domSnapshot.attributeCount * 40;

        domSnapshot.estimatedMemoryUsage = formatBytes(estimatedBytes) + ' (rough estimate)';
        result.detailed.dom = domSnapshot;

        return result;
      }

      // Analyze resource loading performance
      function analyzeResourcePerformance() {
        const result = {
          summary: {},
          resourcesByType: {},
          largestResources: [],
          slowestResources: []
        };

        // Check if Resource Timing API is available
        if (window.performance && performance.getEntriesByType) {
          const resources = performance.getEntriesByType('resource');

          // Summary statistics
          result.summary = {
            totalResources: resources.length,
            totalSize: 0,
            totalLoadTime: 0
          };

          // Group resources by type and calculate statistics
          const resourceTypes = {};
          const sizeByType = {};
          const timeByType = {};

          resources.forEach(resource => {
            // Get resource type
            let type = resource.initiatorType;
            if (!type || type === 'other') {
              // Try to determine type by extension
              const url = resource.name;
              if (url.match(/\\.(?:jpg|jpeg|png|gif|webp|svg|ico)(?:[?#]|$)/i)) {
                type = 'image';
              } else if (url.match(/\\.(?:css)(?:[?#]|$)/i)) {
                type = 'css';
              } else if (url.match(/\\.(?:js)(?:[?#]|$)/i)) {
                type = 'script';
              } else if (url.match(/\\.(?:woff2?|ttf|otf|eot)(?:[?#]|$)/i)) {
                type = 'font';
              } else {
                type = 'other';
              }
            }

            // Count by type
            resourceTypes[type] = (resourceTypes[type] || 0) + 1;

            // Processing time
            const loadTime = resource.responseEnd - resource.startTime;
            timeByType[type] = (timeByType[type] || 0) + loadTime;
            result.summary.totalLoadTime += loadTime;

            // Resource size (can be 0 if CORS prevents access)
            let resourceSize = 0;
            if (resource.transferSize) {
              resourceSize = resource.transferSize;
              sizeByType[type] = (sizeByType[type] || 0) + resourceSize;
              result.summary.totalSize += resourceSize;
            }

            // Add to top resources lists
            result.largestResources.push({
              url: resource.name,
              type: type,
              size: resourceSize,
              loadTime: loadTime
            });

            result.slowestResources.push({
              url: resource.name,
              type: type,
              loadTime: loadTime,
              size: resourceSize
            });
          });

          // Sort and limit largest resources
          result.largestResources.sort((a, b) => b.size - a.size);
          result.largestResources = result.largestResources.slice(0, 10);

          // Sort and limit slowest resources
          result.slowestResources.sort((a, b) => b.loadTime - a.loadTime);
          result.slowestResources = result.slowestResources.slice(0, 10);

          // Format summary with readable sizes
          result.summary.totalSize = formatBytes(result.summary.totalSize);
          result.summary.totalLoadTime = Math.round(result.summary.totalLoadTime) + 'ms';

          // Create resource breakdown by type
          Object.keys(resourceTypes).forEach(type => {
            result.resourcesByType[type] = {
              count: resourceTypes[type],
              totalSize: sizeByType[type] ? formatBytes(sizeByType[type]) : 'unknown',
              totalLoadTime: Math.round(timeByType[type]) + 'ms',
              averageLoadTime: Math.round(timeByType[type] / resourceTypes[type]) + 'ms'
            };
          });
        } else {
          result.error = 'Resource Timing API not available';
        }

        return result;
      }

      // Helper function to get DOM depth
      function getDOMDepth(node, depth = 0) {
        if (!node || !node.children) return depth;

        let maxChildDepth = depth;
        for (let i = 0; i < node.children.length; i++) {
          const childDepth = getDOMDepth(node.children[i], depth + 1);
          maxChildDepth = Math.max(maxChildDepth, childDepth);

          // Limit depth calculation to avoid excessive processing
          if (i > 100) break;
        }

        return maxChildDepth;
      }

      // Helper function to count attributes in the DOM
      function countAttributes() {
        let attributeCount = 0;
        const elements = document.getElementsByTagName('*');
        for (let i = 0; i < elements.length; i++) {
          attributeCount += elements[i].attributes.length;
        }
        return attributeCount;
      }

      // Helper function to estimate number of event listeners
      function estimateEventListeners() {
        const elements = document.getElementsByTagName('*');
        let estimatedListeners = 0;

        // Check for common event attribute patterns
        for (let i = 0; i < elements.length; i++) {
          const element = elements[i];
          const attributes = element.attributes;

          for (let j = 0; j < attributes.length; j++) {
            const attrName = attributes[j].name.toLowerCase();
            if (attrName.startsWith('on')) {
              estimatedListeners++;
            }
          }

          // Check if element has click handler using a heuristic approach
          const style = window.getComputedStyle(element);
          if (style.cursor === 'pointer') {
            estimatedListeners++;
          }
        }

        // Note: This is just an estimation as we can't reliably detect all event listeners
        return estimatedListeners;
      }

      // Helper function to measure event handler performance
      function measureEventHandlers() {
        const result = {
          message: 'Event handler analysis would require longer interaction with the page'
        };

        // This is a simplified version - a comprehensive analysis would require
        // monitoring the page during user interaction
        return result;
      }

      // Helper function to format bytes in a readable format
      function formatBytes(bytes, decimals = 2) {
        if (bytes === 0) return '0 Bytes';

        const k = 1024;
        const dm = decimals < 0 ? 0 : decimals;
        const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB'];

        const i = Math.floor(Math.log(bytes) / Math.log(k));

        return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
      }

      // Combine the results based on the requested analysis type
      const result = {
        url: window.location.href,
        pageTitle: document.title,
        timestamp: new Date().toISOString(),
        userAgent: navigator.userAgent
      };

      const analysisType = '" & analysisType & "';

      if (analysisType === 'page' || analysisType === 'all') {
        result.pagePerformance = analyzePagePerformance();
      }

      if (analysisType === 'javascript' || analysisType === 'all') {
        result.javascriptPerformance = analyzeJavaScriptPerformance();
      }

      if (analysisType === 'memory' || analysisType === 'all') {
        result.memoryUsage = analyzeMemoryUsage();
      }

      if (analysisType === 'resources' || analysisType === 'all') {
        result.resourcePerformance = analyzeResourcePerformance();
      }

      // Add our script's execution time
      result.analysisExecutionTime = (performance.now() - scriptStartTime).toFixed(2) + 'ms';

      return JSON.stringify(result, null, 2);
    })();
  "

  tell application "Safari"
    if not running then
      return "error: Safari is not running."
    end if

    -- If a URL was provided, open it first
    if needToOpenURL then
      try
        tell window 1
          set current tab to (make new tab with properties {URL:testURL})
          delay 3 -- Wait for page to load
        end tell
      on error errMsg
        return "error: Failed to open URL - " & errMsg
      end try
    end if

    try
      if (count of windows) is 0 or (count of tabs of front window) is 0 then
        return "error: No tabs open in Safari."
      end if

      set currentTab to current tab of front window

      -- Execute the JavaScript
      set jsResult to do JavaScript perfJS in currentTab

      return jsResult
    on error errMsg
      return "error: Failed to analyze page performance - " & errMsg & ". Make sure 'Allow JavaScript from Apple Events' is enabled in Safari's Develop menu."
    end try
  end tell
end analyzePerformance

-- Helper function to convert text to lowercase
on toLowerCase(sourceText)
  set lowercaseText to ""
  set upperChars to "ABCDEFGHIJKLMNOPQRSTUVWXYZ"
  set lowerChars to "abcdefghijklmnopqrstuvwxyz"

  repeat with i from 1 to length of sourceText
    set currentChar to character i of sourceText
    set charPos to offset of currentChar in upperChars

    if charPos > 0 then
      set lowercaseText to lowercaseText & character charPos of lowerChars
    else
      set lowercaseText to lowercaseText & currentChar
    end if
  end repeat

  return lowercaseText
end toLowerCase

return my analyzePerformance("--MCP_INPUT:analysisType", "--MCP_INPUT:url")

on run argv
	-- Parse arguments with default values
	set test_type to "all"
	set target_url to ""
	set verbose_mode to false

	-- Process arguments if provided
	if (count of argv) ≥ 1 then
		if item 1 of argv is not "" then
			set test_type to item 1 of argv
		end if
	end if

	if (count of argv) ≥ 2 then
		if item 2 of argv is not "" then
			set target_url to item 2 of argv
		end if
	end if

	if (count of argv) ≥ 3 then
		if item 3 of argv is "true" then
			set verbose_mode to true
		end if
	end if

	-- Check if Safari is running
	tell application "System Events"
		set safariRunning to (exists process "Safari")
	end tell

	if not safariRunning then
		return "{\"error\": \"Safari is not running. Please open Safari and try again.\"}"
	end if

	tell application "Safari"
		-- Navigate to the specified URL if provided
		if target_url is not "" then
			set current_tab to make new document
			set URL of current_tab to target_url
			-- Wait for page to load
			delay 3
		end if

		-- Get current tab information
		set current_tab to current tab of window 1
		set page_url to URL of current_tab

		-- Execute all requested tests
		set test_results to {}

		-- Check if page is using HTTPS
		if test_type is "https" or test_type is "all" then
			set https_result to my checkHttps(page_url, current_tab)
			set test_results to test_results & {https_result}
		end if

		-- Check for mixed content
		if test_type is "mixed-content" or test_type is "all" then
			set mixed_content_result to my checkMixedContent(current_tab)
			set test_results to test_results & {mixed_content_result}
		end if

		-- Check Content Security Policy
		if test_type is "csp" or test_type is "all" then
			set csp_result to my checkCSP(current_tab)
			set test_results to test_results & {csp_result}
		end if

		-- Run basic XSS tests
		if test_type is "xss" or test_type is "all" then
			set xss_result to my checkXSS(current_tab)
			set test_results to test_results & {xss_result}
		end if

		-- Check cookie security
		if test_type is "cookies" or test_type is "all" then
			set cookie_result to my checkCookies(current_tab, verbose_mode)
			set test_results to test_results & {cookie_result}
		end if

		-- Format results as JSON
		set json_result to "{"
		repeat with i from 1 to count of test_results
			set current_result to item i of test_results
			set json_result to json_result & current_result
			if i < count of test_results then
				set json_result to json_result & ", "
			end if
		end repeat
		set json_result to json_result & "}"

		return json_result
	end tell
end run

-- Check if the page is using HTTPS
on checkHttps(page_url, tab_ref)
	set is_https to false

	if page_url starts with "https://" then
		set is_https to true
	end if

	-- Additional certificate verification via JavaScript
	set js_result to ""
	tell application "Safari"
		set js_result to do JavaScript "
			(function() {
				let securityInfo = {
					protocol: window.location.protocol,
					isSecure: window.location.protocol === 'https:',
					host: window.location.host
				};
				return JSON.stringify(securityInfo);
			})();
		" in tab_ref
	end tell

	return "\"https\": {
		\"secure\": " & my boolToString(is_https) & ", 
		\"details\": " & js_result & "
	}"
end checkHttps

-- Check for mixed content on the page
on checkMixedContent(tab_ref)
	tell application "Safari"
		set mixed_content_js to do JavaScript "
			(function() {
				let result = {
					hasMixedContent: false,
					insecureResources: []
				};

				// Check for insecure images
				document.querySelectorAll('img[src^=\"http:\"]').forEach(img => {
					result.hasMixedContent = true;
					result.insecureResources.push({
						type: 'image',
						url: img.src
					});
				});

				// Check for insecure scripts
				document.querySelectorAll('script[src^=\"http:\"]').forEach(script => {
					result.hasMixedContent = true;
					result.insecureResources.push({
						type: 'script',
						url: script.src
					});
				});

				// Check for insecure stylesheets
				document.querySelectorAll('link[rel=\"stylesheet\"][href^=\"http:\"]').forEach(link => {
					result.hasMixedContent = true;
					result.insecureResources.push({
						type: 'stylesheet',
						url: link.href
					});
				});

				// Check for insecure iframes
				document.querySelectorAll('iframe[src^=\"http:\"]').forEach(iframe => {
					result.hasMixedContent = true;
					result.insecureResources.push({
						type: 'iframe',
						url: iframe.src
					});
				});

				// Limit the number of resources to avoid overly large responses
				if (result.insecureResources.length > 10) {
					const count = result.insecureResources.length;
					result.insecureResources = result.insecureResources.slice(0, 10);
					result.insecureResources.push({
						type: 'info',
						message: 'Additional ' + (count - 10) + ' insecure resources not shown'
					});
				}

				return JSON.stringify(result);
			})();
		" in tab_ref
	end tell

	return "\"mixedContent\": " & mixed_content_js
end checkMixedContent

-- Check Content Security Policy implementation
on checkCSP(tab_ref)
	tell application "Safari"
		set csp_js to do JavaScript "
			(function() {
				let result = {
					hasCSP: false,
					policies: {},
					recommendations: []
				};

				// Function to parse CSP header into object
				function parseCSP(cspString) {
					if (!cspString) return {};

					const policies = {};
					const directives = cspString.split(';').map(part => part.trim());

					directives.forEach(directive => {
						if (!directive) return;
						const [key, ...values] = directive.split(' ');
						policies[key] = values.filter(v => v);
					});

					return policies;
				}

				// Try to get CSP meta tag
				const cspMeta = document.querySelector('meta[http-equiv=\"Content-Security-Policy\"]');
				if (cspMeta && cspMeta.content) {
					result.hasCSP = true;
					result.policies['meta'] = parseCSP(cspMeta.content);
				}

				// Check for critical directives
				const criticalDirectives = ['default-src', 'script-src', 'object-src', 'base-uri'];
				const missingDirectives = criticalDirectives.filter(dir => {
					return !result.policies.meta || !result.policies.meta[dir];
				});

				if (missingDirectives.length > 0) {
					result.recommendations.push({
						severity: 'high',
						message: 'Missing critical CSP directives: ' + missingDirectives.join(', ')
					});
				}

				// Check for unsafe inline scripts if CSP is present
				if (result.hasCSP) {
					const scriptSrc = result.policies.meta && result.policies.meta['script-src'];
					if (scriptSrc && (scriptSrc.includes(\"'unsafe-inline'\") || scriptSrc.includes(\"'unsafe-eval'\"))) {
						result.recommendations.push({
							severity: 'medium',
							message: 'CSP allows unsafe inline scripts or eval, which reduces its effectiveness'
						});
					}
				} else {
					result.recommendations.push({
						severity: 'high',
						message: 'No Content Security Policy detected. Implementing CSP can help prevent XSS attacks.'
					});
				}

				return JSON.stringify(result);
			})();
		" in tab_ref
	end tell

	return "\"contentSecurityPolicy\": " & csp_js
end checkCSP

-- Perform basic XSS vulnerability tests
on checkXSS(tab_ref)
	tell application "Safari"
		set xss_js to do JavaScript "
			(function() {
				let result = {
					vulnerabilities: [],
					testsPerformed: []
				};

				// Track tests performed
				result.testsPerformed.push('DOM-based XSS checks');
				result.testsPerformed.push('Input field sanitization checks');

				// Check for vulnerable patterns in JS
				const scripts = Array.from(document.getElementsByTagName('script'));
				const vulnerablePatterns = [
					{ pattern: /document\\.write\\(/g, name: 'document.write()' },
					{ pattern: /eval\\(/g, name: 'eval()' },
					{ pattern: /innerHTML/g, name: 'innerHTML' },
					{ pattern: /outerHTML/g, name: 'outerHTML' }
				];

				scripts.forEach(script => {
					if (!script.textContent) return;

					vulnerablePatterns.forEach(vp => {
						if (vp.pattern.test(script.textContent)) {
							result.vulnerabilities.push({
								type: 'potential-dom-xss',
								detail: `Found potentially unsafe ${vp.name} usage in inline script`,
								severity: 'medium'
							});
						}
					});
				});

				// Check input fields for potential reflection
				const inputs = document.querySelectorAll('input:not([type=password]):not([type=hidden])');
				inputs.forEach(input => {
					result.testsPerformed.push(`Input field check: ${input.name || input.id || 'unnamed'}`);

					// Check if input has event handlers
					const hasInputEvents = input.hasAttribute('onchange') || 
							   input.hasAttribute('oninput') ||
							   input.hasAttribute('onkeyup') ||
							   input.hasAttribute('onkeydown') ||
							   input.hasAttribute('onpaste');

					if (hasInputEvents) {
						result.vulnerabilities.push({
							type: 'input-event-handler',
							detail: `Input field '${input.name || input.id || 'unnamed'}' has inline event handlers which could be XSS vectors`,
							severity: 'low'
						});
					}
				});

				// Safety checks - we're not injecting any real payloads to avoid harming the site
				if (result.vulnerabilities.length === 0) {
					result.vulnerabilities.push({
						type: 'info',
						detail: 'No obvious XSS vulnerabilities detected in basic testing. Note: This does not guarantee the absence of all XSS vulnerabilities.',
						severity: 'info'
					});
				}

				return JSON.stringify(result);
			})();
		" in tab_ref
	end tell

	return "\"xssChecks\": " & xss_js
end checkXSS

-- Check cookie security settings
on checkCookies(tab_ref, verbose_mode)
	tell application "Safari"
		set cookie_js to do JavaScript "
			(function() {
				let result = {
					totalCookies: document.cookie.split(';').filter(c => c.trim()).length,
					insecureCookies: [],
					secureCookies: 0,
					thirdPartyCookies: 0
				};

				// We can't access HttpOnly cookies via JS, so we'll note that
				result.notes = [\"HTTP-only cookies can't be detected via JavaScript\"];

				// For demo purposes, we'll simulate finding some insecure cookies
				// In a real implementation, you would use Safari's document.cookie to analyze accessible cookies

				const cookieString = document.cookie;
				const cookies = cookieString.split(';').map(c => c.trim());

				let hostname = window.location.hostname;
				cookies.forEach(cookie => {
					if (!cookie) return;

					const parts = cookie.split('=');
					const name = parts[0];

					// Check for secure flag in cookie name (this is just a simulation)
					// Real analysis would require checking headers which JS can't do
					const seemsSecure = name.toLowerCase().includes('secure') || 
										name.toLowerCase().includes('token') ||
										name.toLowerCase().includes('auth');

					if (seemsSecure) {
						result.secureCookies++;
					} else {
						// For cookies we can access, assume they're not secure enough
