						});
					}
				});

				// Add some recommendations
				result.recommendations = [];

				if (result.insecureCookies.length > 0) {
					result.recommendations.push({
						severity: 'medium',
						message: 'Some cookies appear to be missing security flags (HttpOnly, Secure, SameSite)'
					});
				}

				// Add recommendation for using modern cookie settings
				result.recommendations.push({
					severity: 'info',
					message: 'For sensitive cookies, use HttpOnly, Secure flags and SameSite=Strict attribute'
				});

				return JSON.stringify(result);
			})();
		" in tab_ref
	end tell

	return "\"cookieSecurity\": " & cookie_js
end checkCookies

-- Helper function to convert boolean to JSON string
on boolToString(boolValue)
	if boolValue then
		return "true"
	else
		return "false"
	end if
end boolToString

on getVSCodeEditorContent()
  set jsToExecute to "
    (async () => {
      try {
        if (typeof vscode !== 'undefined' && vscode.window && vscode.window.activeTextEditor && vscode.env && vscode.env.clipboard) {
          const text = vscode.window.activeTextEditor.document.getText();
          await vscode.env.clipboard.writeText('%%SCRIPT_RESULT_START%%' + text + '%%SCRIPT_RESULT_END%%');
          return 'VSCODE_TEXT_COPIED_WITH_MARKERS';
        } else {
          return 'ERROR: VSCode API not available.';
        }
      } catch (e) {
        return 'ERROR: JS Exception: ' + e.message;
      }
    })()
  "

  tell application "Visual Studio Code" to activate
  delay 0.5

  tell application "System Events"
    tell process "Visual Studio Code"
      set frontmost to true
      key code 34 using {command down, option down} -- Open DevTools
      delay 1.2

      set the clipboard to jsToExecute -- Put the JS itself on clipboard
      delay 0.2
      keystroke "v" using {command down} -- Paste JS code into console
      delay 0.1
      key code 36 -- Execute JS (which puts editor content with markers on clipboard)
      delay 1.0 -- Allow time for JS to run and clipboard to update fully

      -- key code 34 using {command down, option down} -- Optionally close DevTools
    end tell
  end tell

  delay 0.2
  set clipboardContent to (the clipboard as text)

  set text item delimiters to "%%SCRIPT_RESULT_START%%"
  set tempSplit to text items of clipboardContent
  if count of tempSplit > 1 then
    set text item delimiters to "%%SCRIPT_RESULT_END%%"
    set editorText to text item 1 of (text item 2 of tempSplit)
    set text item delimiters to "" -- Reset
    return editorText
  else
    set text item delimiters to "" -- Reset
    if clipboardContent starts with "ERROR:" then
        return "error: " & clipboardContent
    else
        return "error: Could not find expected markers in clipboard. JS might have failed or content was unusual. Clipboard: " & (text 1 thru 100 of clipboardContent)
    end if
  end if
end getVSCodeEditorContent

return my getVSCodeEditorContent()

// Video Conversion Utility
// Converts video files between formats using AVFoundation

function run(argv) {
  // Check if we have command line arguments or are running interactively
  if (argv && argv.length > 0) {
    // MCP mode - parse parameters
    return processMCPParameters(argv);
  } else {
    // Interactive mode
    return performVideoConversion();
  }
}

// Handle MCP parameters
function processMCPParameters(argv) {
  // Parse input parameters from argv
  const inputPath = argv[0] || "";
  const outputPath = argv[1] || "";
  const format = argv[2] || "";
  const quality = argv[3] || "medium";

  // Validate required parameters
  if (!inputPath) {
    return JSON.stringify({success: false, error: "Input path is required"});
  }

  if (!format) {
    return JSON.stringify({success: false, error: "Target format is required"});
  }

  // If output path not specified, create one in the same directory
  let finalOutputPath = outputPath;
  if (!finalOutputPath) {
    const inputFile = $.NSString.alloc.initWithUTF8String(inputPath);
    const directory = inputFile.stringByDeletingLastPathComponent;
    const filename = inputFile.lastPathComponent.stringByDeletingPathExtension;
    finalOutputPath = `${directory}/${filename}.${format}`;
  }

  // Perform the conversion
  return convertVideo(inputPath, finalOutputPath, format, quality);
}

// Interactive video conversion
function performVideoConversion() {
  const app = Application.currentApplication();
  app.includeStandardAdditions = true;

  try {
    // Select input file
    const inputFile = app.chooseFile({
      withPrompt: "Select a video file to convert:",
      ofType: ["public.movie"]
    });
    const inputPath = inputFile.toString();

    // Select output format
    const formats = ["mp4", "mov", "m4v"];
    const selectedFormat = app.chooseFromList(formats, {
      withPrompt: "Convert to which format?",
      defaultItems: ["mp4"]
    });

    if (!selectedFormat || selectedFormat.length === 0) {
      return "Conversion cancelled.";
    }
    const format = selectedFormat[0];

    // Select quality
    const qualityLevels = ["low", "medium", "high", "maximum"];
    const selectedQuality = app.chooseFromList(qualityLevels, {
      withPrompt: "Select quality level:",
      defaultItems: ["medium"]
    });

    if (!selectedQuality || selectedQuality.length === 0) {
      return "Conversion cancelled.";
    }
    const quality = selectedQuality[0];

    // Set output location
    const inputNSString = $.NSString.alloc.initWithUTF8String(inputPath);
    const defaultName = inputNSString.lastPathComponent.stringByDeletingPathExtension.js + "." + format;

    const outputFile = app.chooseFileName({
      withPrompt: "Save converted video as:",
      defaultName: defaultName
    });
    const outputPath = outputFile.toString();

    // Perform conversion
    return convertVideo(inputPath, outputPath, format, quality);
  } catch (error) {
    return "Error: " + error.message;
  }
}

// Video conversion function
function convertVideo(inputPath, outputPath, format, quality) {
  try {
    // Create an AVAsset from the input file
    const inputURL = $.NSURL.fileURLWithPath(inputPath);
    const asset = $.AVURLAsset.alloc.initWithURLOptions(inputURL, null);

    // Determine export preset based on quality
    const preset = getPresetForQuality(quality);

    // Check if the preset is compatible with the asset
    const compatiblePresets = $.AVAssetExportSession.exportPresetsCompatibleWithAsset(asset);
    let presetAvailable = false;

    for (let i = 0; i < compatiblePresets.count; i++) {
      if (compatiblePresets.objectAtIndex(i).js === preset) {
        presetAvailable = true;
        break;
      }
    }

    if (!presetAvailable) {
      return "Error: Quality preset '" + quality + "' is not compatible with this video file.";
    }

    // Create export session
    const exportSession = $.AVAssetExportSession.alloc.initWithAssetPresetName(asset, preset);

    // Set output URL and file type
    exportSession.outputURL = $.NSURL.fileURLWithPath(outputPath);
    exportSession.outputFileType = getOutputFileType(format);

    // Set up completion handler using a dispatch group
    const dispatchGroup = $.NSDispatchGroup.alloc.init;
    dispatchGroup.enter;

    let exportError = null;
    let exportCompleted = false;

    // Export the video
    exportSession.exportAsynchronouslyWithCompletionHandler(function() {
      const status = exportSession.status;

      if (status === $.AVAssetExportSessionStatusCompleted) {
        exportCompleted = true;
      } else if (status === $.AVAssetExportSessionStatusFailed) {
        exportError = exportSession.error.localizedDescription.js;
      } else if (status === $.AVAssetExportSessionStatusCancelled) {
        exportError = "Export was cancelled";
      }

      dispatchGroup.leave;
    });

    // Wait for completion (with timeout)
    const timeout = 60 * 60; // 1 hour in seconds
    const result = dispatchGroup.waitTimeout($.dispatch_time($.DISPATCH_TIME_NOW, timeout * 1000000000));

    if (result !== 0) {
      return "Error: Conversion timed out after " + timeout + " seconds";
    }

    if (exportError) {
      return "Error during conversion: " + exportError;
    }

    if (exportCompleted) {
      return "Video converted to " + format + " format at " + outputPath;
    }

    return "Error: Unknown export status";

  } catch (error) {
    return "Error converting video: " + error.message;
  }
}

// Helper function to get preset based on quality
function getPresetForQuality(quality) {
  switch (quality) {
    case "low":
      return $.AVAssetExportPresetLowQuality;
    case "medium":
      return $.AVAssetExportPresetMediumQuality;
    case "high":
      return $.AVAssetExportPreset1280x720;
    case "maximum":
      return $.AVAssetExportPresetHighestQuality;
    default:
      return $.AVAssetExportPresetMediumQuality;
  }
}

// Helper function to get output file type
function getOutputFileType(format) {
  switch (format.toLowerCase()) {
    case "mp4":
      return $.AVFileTypeMPEG4;
    case "mov":
      return $.AVFileTypeQuickTimeMovie;
    case "m4v":
      return $.AVFileTypeAppleM4V;
    default:
      return $.AVFileTypeMPEG4;
  }
}

// Function to get information about the current Xcode project
function getXcodeProjectInfo() {
  try {
    // Create application objects
    const Xcode = Application('Xcode');
    Xcode.includeStandardAdditions = true;

    // Ensure Xcode is running
    if (!Xcode.running()) {
      return JSON.stringify({
        error: "Xcode is not running"
      });
    }

    // Activate Xcode
    Xcode.activate();

    // Get information about the workspace
    const workspaceDocument = Xcode.workspaceDocument();
    if (!workspaceDocument) {
      return JSON.stringify({
        error: "No workspace document is open"
      });
    }

    // Basic project info
    const projectInfo = {
      name: workspaceDocument.name(),
      filePath: workspaceDocument.file() ? workspaceDocument.file().posixPath() : "Unknown",
    };

    // For advanced info, we need System Events for UI interaction
    const systemEvents = Application('System Events');
    const xcodeProcess = systemEvents.processes.whose({name: 'Xcode'})[0];

    if (xcodeProcess) {
      try {
        // Get active scheme information
        const schemeButton = xcodeProcess.windows[0].buttons.whose({description: {_contains: 'Scheme'}})[0];
        if (schemeButton) {
          projectInfo.activeScheme = schemeButton.name();
        }

        // Get active configuration (Debug/Release)
        const configButton = xcodeProcess.windows[0].buttons.whose({description: {_contains: 'Configuration'}})[0];
        if (configButton) {
          projectInfo.buildConfiguration = configButton.name();
        }

        // Get destination (simulator/device)
        const destinationButton = xcodeProcess.windows[0].buttons.whose({description: {_contains: 'Destination'}})[0];
        if (destinationButton) {
          projectInfo.destination = destinationButton.name();
        }
      } catch (uiError) {
        projectInfo.uiInfoError = "Could not retrieve UI information: " + uiError;
      }
    }

    // Use osascript CLI to get bundle identifier since it can be tricky with JXA
    try {
      const Script = Application('Script Editor');
      const bundleIdScript = `
        tell application "Xcode"
          set infoPlist to info plist of active workspace document
          if infoPlist is not missing value then
            return bundle identifier of infoPlist
          else
            return "Unknown"
          end if
        end tell
      `;

      const result = Script.doScript(bundleIdScript, {in: "AppleScript"});
      if (result && result !== "Unknown") {
        projectInfo.bundleIdentifier = result;
      }
    } catch (bundleIdError) {
      projectInfo.bundleIdError = "Could not retrieve bundle ID: " + bundleIdError;
    }

    return JSON.stringify(projectInfo, null, 2);
  } catch (error) {
    return JSON.stringify({
      error: "Error getting Xcode project info: " + error
    });
  }
}

getXcodeProjectInfo();
